import { useState } from 'react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { AuthProvider } from '@/context/AuthContext';
import { ToastProvider } from '@/context/ToastContext';
import Router from '@/router';
import AppOpeningTransition from '@/components/Layout/AppOpeningTransition';
import ErrorBoundary from '@/components/ErrorBoundary';

const queryClient = new QueryClient({
  defaultOptions: {
    queries: { staleTime: 30_000, retry: 1, refetchOnWindowFocus: false },
  },
});

export default function App() {
  const [showOpening, setShowOpening] = useState(() => {
    if (typeof window === 'undefined') return false;
    if (window.location.pathname.startsWith('/share/receipt')) return false;
    const isReload =
      (performance.getEntriesByType('navigation')[0] as any)?.type === 'reload' ||
      (typeof performance.navigation !== 'undefined' && performance.navigation.type === 1);
    const hasOpened = sessionStorage.getItem('app_opened') === 'true';
    return !isReload && !hasOpened;
  });

  return (
    <ErrorBoundary>
      <QueryClientProvider client={queryClient}>
        <ToastProvider>
          <AuthProvider>
            {showOpening && (
              <AppOpeningTransition
                onComplete={() => {
                  sessionStorage.setItem('app_opened', 'true');
                  setShowOpening(false);
                }}
              />
            )}
            <Router />
          </AuthProvider>
        </ToastProvider>
      </QueryClientProvider>
    </ErrorBoundary>
  );
}

import { api } from './client';
import { AuthUser } from '@/types';

export const authApi = {
  login: (email: string, password: string) =>
    api.post<{ accessToken: string; user: AuthUser }>('/auth/login', {
      email,
      password,
    }),
  me: () => api.get<AuthUser>('/auth/me'),
  resetPassword: (password: string) =>
    api.post<{ success: boolean }>('/auth/reset-password', { password }),
  updateProfile: (data: { name?: string; signature?: string }) =>
    api.put<AuthUser>('/auth/profile', data),
  getPasskeyRegisterOptions: () =>
    api.get<{ options: any; sessionId: string }>('/auth/passkey/register-options'),
  verifyPasskeyRegister: (sessionId: string, credential: any) =>
    api.post<{ success: boolean }>('/auth/passkey/register-verify', {
      sessionId,
      credential,
    }),
  getPasskeyLoginOptions: () =>
    api.get<{ options: any; sessionId: string }>('/auth/passkey/login-options'),
  verifyPasskeyLogin: (sessionId: string, credential: any) =>
    api.post<{ accessToken: string; user: AuthUser }>('/auth/passkey/login-verify', {
      sessionId,
      credential,
    }),
};

import axios from 'axios';
import { Capacitor } from '@capacitor/core';

const isCapacitor = typeof window !== 'undefined' && Capacitor.isNativePlatform();

const getBaseURL = () => {
  const envUrl = import.meta.env.VITE_API_URL;
  let url = envUrl || '/api';

  if (isCapacitor) {
    if (envUrl && envUrl.startsWith('http')) {
      url = envUrl;
    } else {
      url = 'https://guravonlineservices.duckdns.org';
    }
  } else if (envUrl) {
    url = envUrl;
  }

  // Automatically append /api if it is not already present
  if (url !== '/api' && !url.endsWith('/api')) {
    url = url.endsWith('/') ? `${url}api` : `${url}/api`;
  }

  return url;
};

export const api = axios.create({
  baseURL: getBaseURL(),
  headers: { 'Content-Type': 'application/json' },
});

export const nullifyEmptyStrings = (obj: any): any => {
  if (obj === null || obj === undefined) return obj;
  if (typeof obj !== 'object') {
    return obj === '' ? null : obj;
  }
  if (Array.isArray(obj)) {
    return obj.map(nullifyEmptyStrings);
  }
  const cleaned: any = {};
  for (const key in obj) {
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      cleaned[key] = nullifyEmptyStrings(obj[key]);
    }
  }
  return cleaned;
};

// Added debug interceptor to log every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    try {
      const parts = token.split('.');
      if (parts.length === 3) {
        const payload = JSON.parse(atob(parts[1]));
        if (payload && payload.exp && payload.exp * 1000 < Date.now()) {
          localStorage.removeItem('token');
          window.dispatchEvent(new CustomEvent('auth:unauthorized'));
          return Promise.reject(new Error('Token expired'));
        }
      }
    } catch (e) {
      // eslint-disable-next-line no-console
      console.error('[API] Error parsing JWT token:', e);
    }
    config.headers.Authorization = `Bearer ${token}`;
  }

  if (
    config.data &&
    (Object.prototype.toString.call(config.data) === '[object Object]' ||
      Array.isArray(config.data))
  ) {
    config.data = nullifyEmptyStrings(config.data);
  }

  return config;
});

api.interceptors.response.use(
  (res) => {
    if (res.data && res.data.success !== undefined && res.data.data !== undefined) {
      res.data = res.data.data;
    }
    return res;
  },
  (err) => {
    if (err.response?.data && err.response.data.success === false && err.response.data.error) {
      err.response.data.message = err.response.data.error.message;
      err.response.data.statusCode = err.response.data.error.statusCode;
    }
    if (err.response?.status === 401) {
      localStorage.removeItem('token');
      window.dispatchEvent(new CustomEvent('auth:unauthorized'));
    }
    return Promise.reject(err);
  },
);

export function createCrudApi<T>(basePath: string) {
  return {
    getAll: (params?: Record<string, string>) => api.get<T[]>(basePath, { params }),
    getOne: (id: string) => api.get<T>(`${basePath}/${id}`),
    create: (data: unknown) => api.post<T>(basePath, data),
    update: (id: string, data: unknown) => api.put<T>(`${basePath}/${id}`, data),
    delete: (id: string) => api.delete(`${basePath}/${id}`),
  };
}

import { api, createCrudApi } from './client';
import {
  DashboardSummary,
  User,
  PricingMap,
  PricingSetting,
  Customer,
  CustomerDetails,
  Expense,
  ActivityLog,
} from '@/types';

export const dashboardApi = {
  getSummary: (params?: { from?: string; to?: string }) =>
    api.get<DashboardSummary>('/dashboard/summary', { params }),
};

export const usersApi = {
  ...createCrudApi<User>('/users'),
  getOne: undefined as any, // Not used, but just in case
};

export const settingsApi = {
  getPricingMap: () => api.get<PricingMap>('/settings/pricing/map'),
  getAll: () => api.get<PricingSetting[]>('/settings/pricing'),
  updateMany: (updates: Record<string, number>) =>
    api.patch<PricingSetting[]>('/settings/pricing', { updates }),
  resetDefaults: () => api.post<PricingSetting[]>('/settings/pricing/reset'),
  exportSync: (params: { tables: string[] }) =>
    api.get<Blob>('/settings/sync/export', {
      params: { tables: params.tables.join(',') },
      responseType: 'blob',
    }),
  previewSync: (file: File) => {
    const form = new FormData();
    form.append('file', file);
    return api.post('/settings/sync/preview', form, {
      headers: { 'Content-Type': 'multipart/form-data' },
    });
  },
  importSync: (file: File) => {
    const form = new FormData();
    form.append('file', file);
    return api.post('/settings/sync/import', form, {
      headers: { 'Content-Type': 'multipart/form-data' },
      timeout: 600_000,
    });
  },
};

export const customersApi = {
  ...createCrudApi<Customer>('/customers'),
  getOne: (id: string) => api.get<CustomerDetails>(`/customers/${id}`),
  lookup: (phone: string) => api.get<Customer>('/customers/lookup', { params: { phone } }),
};

export const expensesApi = createCrudApi<Expense>('/expenses');

export const activityLogsApi = {
  getAll: (params?: { limit?: number; offset?: number }) =>
    api.get<{ data: ActivityLog[]; total: number }>('/activity-logs', {
      params,
    }),
};

export const publicReceiptsApi = {
  getOne: (type: string, id: string) => api.get<any>(`/public-receipts/${type}/${id}`),
};

export const referencesApi = {
  getAll: (params?: { search?: string; page?: number; limit?: number }) =>
    api.get<{ data: any[]; total: number; page: number; limit: number }>('/references', { params }),
};

import { useEffect } from 'react';
import { useForm, Controller } from 'react-hook-form';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { zodResolver } from '@hookform/resolvers/zod';
import { affidavitsApi } from '@/api';
import { PaperType, AuthorizerType, Affidavit } from '@/types';
import { usePricing, calcAffidavitTotal } from '@/hooks/usePricing';
import { useCustomerLookup } from '@/hooks/useCustomerLookup';
import { useCustomerNameSearch } from '@/hooks/useCustomerNameSearch';
import { createAffidavitSchema } from '@/utils/validation';
import NeoSelect from '@/components/NeoSelect';
import NeoDatePicker from '@/components/NeoDatePicker';

interface FormValues {
  customerName: string;
  phone: string;
  purpose: string;
  affidavitNo?: string;
  paperType: PaperType;
  authorizerType: AuthorizerType;
  authorizerName: string;
  dateOfService: string;
  amountCharged: number;
  notaryPublicFee?: number;
  remark?: string;
  customerBroughtStamp?: 'Yes' | 'No';
}

interface NewRecordFormProps {
  onSaveSuccess: (record: Affidavit) => void;
}

const TODAY = () => new Date().toISOString().split('T')[0];

const EMPTY_FORM: FormValues = {
  customerName: '',
  phone: '',
  purpose: '',
  affidavitNo: '',
  paperType: '' as any,
  authorizerType: '' as any,
  authorizerName: '',
  dateOfService: TODAY(),
  amountCharged: 0,
  notaryPublicFee: undefined,
  remark: '',
  customerBroughtStamp: undefined,
};

export default function NewRecordForm({ onSaveSuccess }: NewRecordFormProps) {
  const qc = useQueryClient();
  const { pricing } = usePricing();
  const today = TODAY();

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    reset,
    control,
    formState: { errors },
  } = useForm<FormValues>({
    defaultValues: { ...EMPTY_FORM, dateOfService: today },
    resolver: zodResolver(createAffidavitSchema(pricing)),
    mode: 'onTouched',
  });

  const paperWatch = watch('paperType');
  const authWatch = watch('authorizerType');
  const phoneWatch = watch('phone');
  const customerNameWatch = watch('customerName');
  const amountChargedWatch = watch('amountCharged');
  const customerBroughtStampWatch = watch('customerBroughtStamp');

  // ΓöÇΓöÇ Customer auto-fill ΓöÇΓöÇ
  const { showAutoFillIndicator, resetIndicator } = useCustomerLookup(phoneWatch, (customer) =>
    setValue('customerName', customer.name, { shouldValidate: true }),
  );

  const { suggestions, setSuggestions } = useCustomerNameSearch(customerNameWatch);

  // ΓöÇΓöÇ Stamp radio reset on paper type change ΓöÇΓöÇ
  useEffect(() => {
    if (paperWatch === 'stamp500') {
      setValue('customerBroughtStamp', 'No');
    } else {
      setValue('customerBroughtStamp', undefined);
    }
  }, [paperWatch, setValue]);

  // ΓöÇΓöÇ Price calculation ΓöÇΓöÇ
  const formCalc =
    paperWatch && authWatch
      ? (() => {
          const res = calcAffidavitTotal(paperWatch, authWatch, pricing);
          if (paperWatch === 'stamp500' && customerBroughtStampWatch === 'Yes') {
            return {
              ...res,
              paperCost: 0,
              total: res.authFee,
            };
          }
          return res;
        })()
      : null;

  const isDiscounted =
    !!formCalc && amountChargedWatch !== undefined && Number(amountChargedWatch) < formCalc.total;

  useEffect(() => {
    if (formCalc) {
      setValue('amountCharged', formCalc.total);
    }
  }, [formCalc, setValue]);

  useEffect(() => {
    if (!isDiscounted) {
      setValue('remark', '');
    }
  }, [isDiscounted, setValue]);

  // ΓöÇΓöÇ Mutation ΓöÇΓöÇ
  const mutation = useMutation({
    mutationFn: (data: FormValues) => {
      const payload = {
        ...data,
        customerBroughtStamp: data.customerBroughtStamp === 'Yes',
      };
      return affidavitsApi.create(payload as any).then((r) => r.data);
    },
    onSuccess: (data) => {
      qc.invalidateQueries({ queryKey: ['affidavits'] });
      qc.invalidateQueries({ queryKey: ['dashboard'] });
      resetIndicator();
      onSaveSuccess(data);
      reset({ ...EMPTY_FORM, dateOfService: today });
    },
  });

  // ΓöÇΓöÇ Render ΓöÇΓöÇ
  return (
    <div className="card" style={{ maxWidth: 600, marginTop: '1.5rem' }}>
      <div style={{ fontWeight: 500, marginBottom: '1rem' }}>New affidavit record</div>
      {mutation.isError && (
        <div className="alert-error" style={{ marginBottom: 16 }}>
          Failed to save. Please try again.
        </div>
      )}
      <form onSubmit={handleSubmit((d) => mutation.mutate(d))}>
        <div className="grid-2">
          <div className="form-group" style={{ position: 'relative' }}>
            <label>Customer name *</label>
            <input {...register('customerName')} placeholder="Full name" autoComplete="off" />
            {errors.customerName && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>
                {errors.customerName.message}
              </span>
            )}
            {showAutoFillIndicator && (
              <span
                style={{ color: 'var(--success)', fontSize: 11, display: 'block', marginTop: 4 }}
              >
                Γ£ô Auto-filled from customer profile
              </span>
            )}
            {suggestions.length > 0 && (
              <div
                style={{
                  position: 'absolute',
                  top: '100%',
                  left: 0,
                  right: 0,
                  background: 'var(--surface)',
                  border: '2.5px solid var(--border)',
                  borderRadius: 'var(--radius)',
                  boxShadow: 'var(--neo-shadow-sm)',
                  zIndex: 50,
                  maxHeight: '180px',
                  overflowY: 'auto',
                  marginTop: 4,
                }}
              >
                {suggestions.map((cust) => (
                  <div
                    key={cust.id}
                    onClick={() => {
                      setValue('customerName', cust.name, { shouldValidate: true });
                      setValue('phone', cust.phone || '', { shouldValidate: true });
                      setSuggestions([]);
                    }}
                    style={{
                      padding: '8px 12px',
                      cursor: 'pointer',
                      borderBottom: '1.5px solid var(--border-light)',
                      textAlign: 'left',
                    }}
                    onMouseEnter={(e) => (e.currentTarget.style.background = 'var(--bg)')}
                    onMouseLeave={(e) => (e.currentTarget.style.background = 'transparent')}
                  >
                    <div style={{ fontWeight: 700, fontSize: '13px', color: 'var(--text)' }}>
                      {cust.name}
                    </div>
                    {cust.phone && (
                      <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: 2 }}>
                        ≡ƒô₧ {cust.phone}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
          <div className="form-group">
            <label>Phone number</label>
            <input {...register('phone')} placeholder="Mobile number" />
            {errors.phone && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>{errors.phone.message}</span>
            )}
          </div>
        </div>
        <div className="form-group">
          <label>Affidavit purpose / type *</label>
          <input
            {...register('purpose')}
            placeholder="e.g. Name correction, Income proof, Residence proof"
          />
          {errors.purpose && (
            <span style={{ color: 'var(--danger)', fontSize: 12 }}>{errors.purpose.message}</span>
          )}
        </div>
        <div className="form-group">
          <label>Affidavit No.</label>
          <input {...register('affidavitNo')} placeholder="e.g. 12345/2026 (Optional)" />
          {errors.affidavitNo && (
            <span style={{ color: 'var(--danger)', fontSize: 12 }}>
              {errors.affidavitNo.message}
            </span>
          )}
        </div>
        <div className="grid-2">
          <div className="form-group">
            <label>Paper type *</label>
            <Controller
              control={control}
              name="paperType"
              render={({ field: { value, onChange } }) => (
                <NeoSelect
                  value={value || ''}
                  onChange={onChange}
                  options={[
                    { value: 'stamp500', label: `Γé╣${pricing.stamp500_cost} Stamp Paper` },
                    { value: 'Plain', label: 'Plain Paper' },
                  ]}
                  placeholder="Select"
                />
              )}
            />
            {errors.paperType && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>
                {errors.paperType.message}
              </span>
            )}
          </div>
          <div className="form-group">
            <label>Authorized by *</label>
            <Controller
              control={control}
              name="authorizerType"
              render={({ field: { value, onChange } }) => (
                <NeoSelect
                  value={value || ''}
                  onChange={onChange}
                  options={[
                    {
                      value: 'magistrate',
                      label: `Executive Magistrate (Γé╣${pricing.magistrate_fee})`,
                    },
                    { value: 'Notary', label: `Notary Public (Γé╣${pricing.notary_fee})` },
                  ]}
                  placeholder="Select"
                />
              )}
            />
            {errors.authorizerType && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>
                {errors.authorizerType.message}
              </span>
            )}
          </div>
        </div>

        {paperWatch === 'stamp500' && (
          <div className="form-group" style={{ marginBottom: 16 }}>
            <label>Stamp? *</label>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 20, marginTop: 6 }}>
              <label
                style={{
                  display: 'flex',
                  gap: 6,
                  alignItems: 'center',
                  cursor: 'pointer',
                  fontSize: 14,
                }}
              >
                <input type="radio" value="Yes" {...register('customerBroughtStamp')} />
                Without stamp
              </label>
              <label
                style={{
                  display: 'flex',
                  gap: 6,
                  alignItems: 'center',
                  cursor: 'pointer',
                  fontSize: 14,
                }}
              >
                <input type="radio" value="No" {...register('customerBroughtStamp')} />
                With Stamp
              </label>
            </div>
            {errors.customerBroughtStamp && (
              <span
                style={{ color: 'var(--danger)', fontSize: 12, display: 'block', marginTop: 4 }}
              >
                {errors.customerBroughtStamp.message}
              </span>
            )}
          </div>
        )}

        {authWatch === 'Notary' && (
          <div className="form-group">
            <label>Notary Public fee to deduct (Γé╣) *</label>
            <input
              type="number"
              {...register('notaryPublicFee', { valueAsNumber: true })}
              placeholder="Amount paid to Notary Public"
            />
            {errors.notaryPublicFee && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>
                {errors.notaryPublicFee.message}
              </span>
            )}
          </div>
        )}
        <div className="grid-2">
          <div className="form-group">
            <label>Authorizer name</label>
            <input {...register('authorizerName')} placeholder="Name of magistrate or notary" />
            {errors.authorizerName && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>
                {errors.authorizerName.message}
              </span>
            )}
          </div>
          <div className="form-group">
            <label>Date of service *</label>
            <Controller
              control={control}
              name="dateOfService"
              render={({ field: { value, onChange } }) => (
                <NeoDatePicker value={value} onChange={onChange} max={today} />
              )}
            />
            {errors.dateOfService && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>
                {errors.dateOfService.message}
              </span>
            )}
          </div>
        </div>

        {/* Calculations Breakdown */}
        {formCalc && (
          <div className="price-box" style={{ marginBottom: 14 }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              {formCalc.paperCost > 0 && (
                <div className="price-row">
                  <span>Stamp paper cost</span>
                  <span>Γé╣{formCalc.paperCost}</span>
                </div>
              )}
              <div className="price-row">
                <span>
                  {authWatch === 'magistrate' ? 'Executive Magistrate' : 'Notary Public'} Fee
                </span>
                <span>Γé╣{formCalc.authFee}</span>
              </div>
              <div className="divider" style={{ margin: '8px 0' }} />
              <div className="price-row" style={{ fontWeight: 700, fontSize: 15 }}>
                <span>Calculated Total</span>
                <span>Γé╣{formCalc.total}</span>
              </div>
            </div>
          </div>
        )}

        {/* Fee Charged Input */}
        <div className="form-group">
          <label>Amount charged (Γé╣) *</label>
          <input
            type="number"
            {...register('amountCharged', { valueAsNumber: true })}
            placeholder="Standard fee auto-filled"
          />
          {errors.amountCharged && (
            <span style={{ color: 'var(--danger)', fontSize: 12 }}>
              {errors.amountCharged.message}
            </span>
          )}
        </div>

        {/* Remark field for discounts */}
        {isDiscounted && (
          <div className="form-group" style={{ animation: 'fadeIn 0.2s ease' }}>
            <label style={{ color: 'var(--danger)', fontWeight: 700 }}>
              Reason for discount (Remark) *
            </label>
            <input
              {...register('remark')}
              placeholder="e.g. Regular customer, special request"
              style={{ borderColor: 'var(--danger)' }}
            />
            {errors.remark && (
              <span style={{ color: 'var(--danger)', fontSize: 12 }}>{errors.remark.message}</span>
            )}
          </div>
        )}

        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginTop: 4 }}>
          <button className="btn btn-primary" type="submit" disabled={mutation.isPending}>
            {mutation.isPending ? 'SavingΓÇª' : 'Save record'}
          </button>
          <button
            type="button"
            className="btn"
            onClick={() => {
              resetIndicator();
              reset({ ...EMPTY_FORM, dateOfService: today });
            }}
          >
            Clear
          </button>
        </div>
      </form>
    </div>
  );
}

import { useState } from 'react';
import { CustomerDetails, CustomerServiceUsage } from '@/types';
import { generateMessageUrl } from '@/utils/messageTemplates';
import { messageLogsApi } from '@/api';

interface CustomerShareReceiptModalProps {
  service: CustomerServiceUsage;
  customer: CustomerDetails;
  onClose: () => void;
}

const STORAGE_KEY = 'quick_message_templates';

function getTemplateBody(serviceTypeName: string): string {
  // Try to find a stored override for a matching module-level template
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      const parsed = JSON.parse(stored);
      // Use the first matching receipt template if user has customised one
      const found = parsed.find((t: any) => t.id === 'generic_receipt_shared');
      if (found?.body) return found.body;
    }
  } catch {
    /* fall through */
  }
  return (
    `Dear {CustomerName},\n\n` +
    `Please find the link to view your receipt for the ${serviceTypeName} service:\n` +
    `{ReceiptUrl}\n\n` +
    `Thank you.\nGURAV ONLINE SERVICES`
  );
}

export default function CustomerShareReceiptModal({
  service,
  customer,
  onClose,
}: CustomerShareReceiptModalProps) {
  const receiptUrl = `${window.location.origin}/share/receipt/${service.type}/${service.id}`;
  const defaultPhone = (customer.phone || '').replace(/^\+91/, '').replace(/\D/g, '');
  const defaultName = customer.name || '';

  const buildMessage = (name: string) =>
    getTemplateBody(service.typeName)
      .replace(/{CustomerName}/g, name)
      .replace(/{ReceiptUrl}/g, receiptUrl);

  const [name, setName] = useState(defaultName);
  const [phone, setPhone] = useState(defaultPhone);
  const [message, setMessage] = useState(() => buildMessage(defaultName));

  const handleNameChange = (val: string) => {
    setName(val);
