  const kmcGrossPct = hasEarnings
    ? Math.max(0, Math.round(((modules.kmc?.grossEarnings || 0) / totalEarnings) * 100))
    : 0;
  const cscGrossPct = hasEarnings
    ? Math.max(0, Math.round(((modules.csc?.grossEarnings || 0) / totalEarnings) * 100))
    : 0;
  const aapleSarkarGrossPct = hasEarnings ? Math.max(0, 100 - kmcGrossPct - cscGrossPct) : 0;

