    ? Math.max(0, Math.round(((modules.kmc?.netEarnings || 0) / totalNetEarnings) * 100))
    : 0;
  const cscNetPct = hasNetEarnings
    ? Math.max(0, Math.round(((modules.csc?.netEarnings || 0) / totalNetEarnings) * 100))
    : 0;
