                    background: 'rgb(5, 150, 105)',
                    transition: 'width 0.3s ease',
                  }}
                  title={`Aaple Sarkar: ${aapleSarkarNetPct}%`}
                />
              )}
              {cscNetPct > 0 && (
                <div
                  style={{
                    width: `${cscNetPct}%`,
                    background: 'rgb(217, 119, 6)',
                    transition: 'width 0.3s ease',
                  }}
                  title={`CSC: ${cscNetPct}%`}
                />
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
