import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { expensesApi } from '../api';
import NeoDatePicker from './NeoDatePicker';
import NeoSelect from './NeoSelect';

interface ExpensesModalProps {
  user: {
    id: string;
    name: string;
    role: string;
  };
  onClose: () => void;
}

const SHOP_TYPES = [
  'Monthly Electricity Bill',
  'Yearly Property Tax',
  'Monthly Property Rent',
  'Paper Ream',
  'Xerox Machine Maintenance',
  'Daily Tea & Snacks',
  'Daily Affidavit Xerox',
  'KMC Employee Payout',
  'Other',
];

const HOME_TYPES = [
  'Weekly Grocery',
  'LPG Cylinder',
  'TV Cable Recharge',
  'Mobile Recharge',
  'Petrol',
  'Home Electricity Bill',
  'Monthly Flat Maintenance',
  'Medicines',
  'Personal Well-beings',
  'Hotel Expense',
  'Travel Expense',
  'Ceremony Gifts Expense',
  'Other',
];

export default function ExpensesModal({ user, onClose }: ExpensesModalProps) {
  const qc = useQueryClient();
  const [category, setCategory] = useState<'Shop' | 'Home'>('Shop');
  const [type, setType] = useState<string>('Monthly Electricity Bill');
  const [customType, setCustomType] = useState<string>('');
  const [amount, setAmount] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [description, setDescription] = useState<string>('');

  // KMC Employee fields
  const [empName, setEmpName] = useState<string>('');
  const [empDate, setEmpDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const [err, setErr] = useState<string>('');

  // Fetch expenses
  const { data: expenses = [], isLoading } = useQuery({
    queryKey: ['expenses', user.id],
    queryFn: () => expensesApi.getAll({ userId: user.id }).then((r) => r.data),
  });

  // Create expense
  const createMutation = useMutation({
    mutationFn: (payload: any) => expensesApi.create(payload),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['expenses', user.id] });
      qc.invalidateQueries({ queryKey: ['dashboard'] });
      // Reset form
      setAmount('');
      setCustomType('');
      setDescription('');
      setEmpName('');
      setErr('');
    },
    onError: (e: any) => {
      setErr(e?.response?.data?.message || 'Failed to save expense.');
    },
  });

  // Delete expense
  const deleteMutation = useMutation({
    mutationFn: (id: string) => expensesApi.delete(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['expenses', user.id] });
      qc.invalidateQueries({ queryKey: ['dashboard'] });
    },
  });

  const handleCategoryChange = (cat: 'Shop' | 'Home') => {
    setCategory(cat);
    if (cat === 'Shop') {
      setType(SHOP_TYPES[0]);
    } else {
      setType(HOME_TYPES[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || Number(amount) <= 0) {
      setErr('Please enter a valid amount.');
      return;
    }

    let finalType = type;
    if (type === 'Other') {
      if (!customType.trim()) {
        setErr('Please specify the custom expense type.');
        return;
      }
      finalType = customType.trim();
    }

    let finalDesc = description.trim();
    if (type === 'KMC Employee Payout') {
      if (!empName.trim()) {
        setErr("Please specify the employee's name.");
        return;
      }
      finalDesc = `Employee: ${empName.trim()}, Payout Date: ${empDate}. ${finalDesc}`.trim();
    }

    createMutation.mutate({
      category,
      type: finalType,
      amount: parseFloat(amount),
      date,
      description: finalDesc || null,
      userId: user.id,
    });
  };

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(0,0,0,0.3)',
        zIndex: 100,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '1rem',
      }}
    >
      <div
        className="card"
        style={{
          width: '100%',
          maxWidth: 750,
          maxHeight: '92vh',
          overflowY: 'auto',
          position: 'relative',
          padding: '1.5rem',
        }}
      >
        <button
          onClick={onClose}
          style={{
            position: 'absolute',
            top: '1rem',
            right: '1rem',
            background: 'none',
            border: 'none',
            fontSize: 18,
            cursor: 'pointer',
            color: 'var(--text-muted)',
          }}
        >
          Γ£ò
        </button>

        <div style={{ fontWeight: 700, fontSize: 18, marginBottom: '1.25rem' }}>
          Expenses ΓÇö {user.name} ({user.role})
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
          {/* Add Expense Form */}
          <div style={{ borderRight: '1px solid var(--border)', paddingRight: '1.5rem' }}>
            <div
              style={{
                fontWeight: 600,
                fontSize: 14,
                marginBottom: 12,
                borderBottom: '1px solid var(--border)',
                paddingBottom: 6,
              }}
            >
              Declare Expense
            </div>
            <form onSubmit={handleSubmit}>
              <div className="form-group" style={{ marginBottom: 12 }}>
                <label>Category</label>
                <div style={{ display: 'flex', gap: 8 }}>
                  <button
                    type="button"
                    className={`btn btn-sm ${category === 'Shop' ? 'btn-primary' : ''}`}
                    onClick={() => handleCategoryChange('Shop')}
                    style={{ flex: 1 }}
                  >
                    Shop
                  </button>
                  <button
                    type="button"
                    className={`btn btn-sm ${category === 'Home' ? 'btn-primary' : ''}`}
                    onClick={() => handleCategoryChange('Home')}
                    style={{ flex: 1 }}
                  >
                    Home
                  </button>
                </div>
              </div>

              <div className="form-group" style={{ marginBottom: 12 }}>
                <label>Expense Type</label>
                <NeoSelect
                  value={type}
                  onChange={(val) => setType(val)}
                  options={(category === 'Shop' ? SHOP_TYPES : HOME_TYPES).map((t) => ({
                    value: t,
                    label: t,
                  }))}
                />
              </div>

              {type === 'Other' && (
                <div className="form-group" style={{ marginBottom: 12 }}>
                  <label>Specify Type *</label>
                  <input
                    value={customType}
                    onChange={(e) => setCustomType(e.target.value)}
                    placeholder="e.g. Paper Ream Brand X"
                  />
                </div>
              )}

              {type === 'KMC Employee Payout' && (
                <div
                  style={{
                    background: 'var(--bg)',
                    padding: 8,
                    borderRadius: 4,
                    marginBottom: 12,
                    border: '1px solid var(--border-light)',
                  }}
                >
                  <div className="form-group" style={{ marginBottom: 8 }}>
                    <label>Employee Name *</label>
                    <input
                      value={empName}
                      onChange={(e) => setEmpName(e.target.value)}
                      placeholder="Name of employee"
                    />
                  </div>
                  <div className="form-group" style={{ marginBottom: 4 }}>
                    <label>Payout Date *</label>
                    <NeoDatePicker value={empDate} onChange={(val) => setEmpDate(val)} />
                  </div>
                </div>
              )}

              <div className="grid-2" style={{ marginBottom: 12 }}>
                <div className="form-group">
                  <label>Amount (Γé╣) *</label>
                  <input
                    type="number"
                    value={amount}
                    onChange={(e) => setAmount(e.target.value)}
                    placeholder="Amount spent"
                  />
                </div>
                <div className="form-group">
                  <label>Date *</label>
                  <NeoDatePicker value={date} onChange={(val) => setDate(val)} />
                </div>
              </div>

              <div className="form-group" style={{ marginBottom: 12 }}>
                <label>Description / Remarks</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder="Additional details..."
                  rows={2}
                  style={{
                    width: '100%',
                    padding: 8,
                    border: '1px solid var(--border)',
                    borderRadius: 4,
                    resize: 'vertical',
                  }}
                />
              </div>

              {err && (
                <div className="alert-error" style={{ marginBottom: 12 }}>
                  {err}
                </div>
              )}

              <button
                type="submit"
                className="btn btn-primary"
                style={{ width: '100%' }}
                disabled={createMutation.isPending}
              >
                {createMutation.isPending ? 'SavingΓÇª' : 'Add Expense'}
              </button>
            </form>
          </div>

          {/* Expenses List */}
          <div>
            <div
              style={{
                fontWeight: 600,
                fontSize: 14,
                marginBottom: 12,
                borderBottom: '1px solid var(--border)',
                paddingBottom: 6,
              }}
            >
              Recent Expenses
            </div>
            {isLoading ? (
              <div style={{ color: 'var(--text-muted)', fontSize: 13 }}>LoadingΓÇª</div>
            ) : expenses.length === 0 ? (
              <div
                style={{
                  color: 'var(--text-muted)',
                  fontSize: 13,
                  textAlign: 'center',
                  marginTop: '2rem',
                }}
              >
                No expenses declared.
              </div>
            ) : (
              <div
                style={{
                  overflowY: 'auto',
                  maxHeight: '48vh',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 8,
                }}
              >
                {expenses.map((e) => (
                  <div
                    key={e.id}
                    style={{
                      background: 'var(--surface)',
                      border: '2.5px solid var(--border)',
                      borderRadius: 'var(--radius)',
                      padding: 10,
                      boxShadow: '2px 2px 0px var(--border)',
                      position: 'relative',
                      fontSize: 12,
                    }}
                  >
                    <div
                      style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        fontWeight: 700,
                        marginBottom: 4,
                      }}
                    >
                      <span
                        style={{
                          color: e.category === 'Shop' ? 'var(--primary)' : 'var(--success)',
                        }}
                      >
                        {e.category} / {e.type}
                      </span>
                      <span style={{ color: 'rgb(220, 38, 38)' }}>
                        Γé╣{Number(e.amount).toLocaleString('en-IN')}
                      </span>
                    </div>
                    <div style={{ color: 'var(--text-muted)', marginBottom: 2 }}>
                      Date: {e.date}
                    </div>
                    {e.description && (
                      <div
                        style={{
                          background: 'var(--bg)',
                          padding: '4px 6px',
                          borderRadius: 4,
                          fontStyle: 'italic',
                          wordBreak: 'break-word',
                        }}
                      >
                        {e.description}
                      </div>
                    )}
                    <button
                      onClick={() => {
                        if (confirm('Delete this expense?')) {
                          deleteMutation.mutate(e.id);
                        }
                      }}
                      style={{
                        position: 'absolute',
                        bottom: 8,
                        right: 8,
                        background: 'none',
                        border: 'none',
                        color: 'var(--danger)',
                        cursor: 'pointer',
                        fontWeight: 700,
                        fontSize: 11,
                      }}
                    >
                      Delete
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { NavLink, useLocation } from 'react-router-dom';

export interface ServiceItem {
  to: string;
  label: string;
}

export interface ServiceGroup {
  label: string;
  items: ServiceItem[];
  activePaths: string[];
}

export function DesktopDropdown({
  group,
  onNavigate,
}: {
  group: ServiceGroup;
  onNavigate: (to: string) => void;
}) {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();
  const isActive = group.activePaths.includes(location.pathname);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const timeoutRef = useRef<any>(null);

  useEffect(() => {
    setIsOpen(false);
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }
  }, [location.pathname]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  const handleMouseEnter = () => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
      timeoutRef.current = null;
    }
    setIsOpen(true);
  };

  const handleMouseLeave = () => {
    timeoutRef.current = setTimeout(() => {
      setIsOpen(false);
    }, 200);
  };

  return (
    <div
      ref={dropdownRef}
      className="nav-dropdown-container"
      style={{ position: 'relative' }}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        className={`nav-item ${isActive ? 'active' : ''}`}
        style={{
          cursor: 'pointer',
          background: isActive ? 'var(--accent-light)' : 'transparent',
          border: '2px solid transparent',
          outline: 'none',
        }}
      >
        <span>{group.label}</span>
        <span
          style={{
            fontSize: 9,
            marginLeft: 6,
            display: 'inline-block',
            transform: isOpen ? 'rotate(180deg)' : 'none',
            transition: 'transform 0.1s',
          }}
        >
          Γû╝
        </span>
      </button>

      {isOpen && (
        <div
          style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            background: 'var(--surface)',
            border: '3px solid var(--border)',
            borderRadius: '8px',
            boxShadow: '4px 4px 0px var(--border)',
            padding: '6px 0',
            minWidth: 180,
            zIndex: 100,
            marginTop: 4,
          }}
        >
          {group.items.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              onClick={(e) => {
                if (e.button === 0 && !e.metaKey && !e.altKey && !e.ctrlKey && !e.shiftKey) {
                  e.preventDefault();
                  onNavigate(item.to);
                }
              }}
              className={({ isActive }) => `dropdown-item ${isActive ? 'active' : ''}`}
              style={({ isActive }) => ({
                display: 'block',
                padding: '10px 16px',
                fontSize: '13px',
                fontWeight: 700,
                color: 'var(--text)',
                textDecoration: 'none',
                background: isActive ? 'var(--accent-light)' : 'transparent',
                borderBottom: '1px solid var(--border-light)',
              })}
            >
              {item.label}
            </NavLink>
          ))}
        </div>
      )}
    </div>
  );
}

export function MobileAccordion({
  group,
  onCloseMenu,
  onNavigate,
}: {
  group: ServiceGroup;
  onCloseMenu: () => void;
  onNavigate: (to: string) => void;
}) {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();
  const isActive = group.activePaths.includes(location.pathname);

  return (
    <div style={{ borderBottom: '2.5px solid var(--border)' }}>
      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        style={{
          width: '100%',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '14px 20px',
          fontSize: 15,
          fontWeight: 700,
          background: isActive ? 'var(--accent-light)' : 'transparent',
          color: 'var(--text)',
          border: 'none',
          textAlign: 'left',
          cursor: 'pointer',
          outline: 'none',
        }}
      >
        <span>{group.label}</span>
        <span style={{ fontSize: 11 }}>{isOpen ? 'Γû▓' : 'Γû╝'}</span>
      </button>

      {isOpen && (
        <div
          style={{
            background: 'var(--bg)',
            borderTop: '2.5px solid var(--border)',
          }}
        >
          {group.items.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              onClick={(e) => {
                if (e.button === 0 && !e.metaKey && !e.altKey && !e.ctrlKey && !e.shiftKey) {
                  e.preventDefault();
                  onCloseMenu();
                  onNavigate(item.to);
                }
              }}
              className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
              style={({ isActive }) => ({
                display: 'flex',
                padding: '14px 30px',
                fontSize: 14,
                fontWeight: 700,
                color: 'var(--text)',
                textDecoration: 'none',
                background: isActive ? 'var(--accent-light)' : 'transparent',
                borderBottom: '1px solid var(--border-light)',
                borderRadius: 0,
                borderLeft: '3px solid transparent',
              })}
            >
              <span>{item.label}</span>
            </NavLink>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { useForm, FormProvider } from 'react-hook-form';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { marriagesApi, settingsApi } from '@/api';
import { MarriageTicket, Marriage, MarriageAct, ProofEntry } from '@/types';
import { getTicketAffidavitPurposes, getTicketBreakdown, getEntryAmount } from './helpers';
import { useCustomerLookup } from '@/hooks/useCustomerLookup';

// Subcomponents & Hooks
import { useOfficialFee } from './hooks/useOfficialFee';
import { useAffidavitLinker } from './hooks/useAffidavitLinker';
import CustomerSection from './components/CustomerSection';
import MarriageDetailsSection from './components/MarriageDetailsSection';
import ServicesSection from './components/ServicesSection';
import AffidavitListSection from './components/AffidavitListSection';

interface RecordFormValues {
  contactName: string;
  phone: string;
  contactEmail?: string;
  address?: string;
  isPrimaryContactSpouse?: boolean;
  primaryContactSpouseType?: 'husband' | 'wife' | null;
  spouse1Name: string;
  spouse2Name: string;
  marriageAct: MarriageAct;
  marriageDate: string;
  marriagePlace: string;
  appointmentDate?: string;
  affidavitDates?: Record<string, string>;
  dateOfService: string;
  servicesProvided: string[];
  affidavitIds: string[];
  amountCharged: number;
  officialFee?: number;
  courtFeeTickets?: number;
  miscFee?: number;
  consultancyFee?: number;
  ticketId?: string;
  applicationNo?: string;
}

interface AddRecordTabProps {
  prefillTicket: MarriageTicket | null;
  prefillMode?: 'save_ticket' | 'complete_record';
  onClearPrefill: () => void;
  onSaveSuccess: (record: Marriage) => void;
  onSaveTicketSuccess?: (ticket: MarriageTicket) => void;
  pricing: Record<string, number>;
  servicesDef: { key: string; cost: number }[];
}

export default function AddRecordTab({
  prefillTicket,
  prefillMode = 'complete_record',
  onClearPrefill,
  onSaveSuccess,
  onSaveTicketSuccess,
  pricing,
  servicesDef,
}: AddRecordTabProps) {
  const qc = useQueryClient();
  const today = new Date().toISOString().split('T')[0];

  const [affidavitsPaidSeparately, setAffidavitsPaidSeparately] = useState(() => {
    return pricing.marriage_affidavits_paid_separately !== 0;
  });

  useEffect(() => {
    if (pricing.marriage_affidavits_paid_separately !== undefined) {
      setAffidavitsPaidSeparately(pricing.marriage_affidavits_paid_separately !== 0);
    }
  }, [pricing.marriage_affidavits_paid_separately]);

  const methods = useForm<RecordFormValues>({
    defaultValues: {
      dateOfService: today,
      servicesProvided: ['Misc (Form - Xerox Copies)'],
      miscFee: pricing.marriage_misc_fee ?? 0,
      consultancyFee: pricing.marriage_consultancy_fee ?? 500,
      affidavitIds: [],
      affidavitDates: {},
      isPrimaryContactSpouse: true,
      primaryContactSpouseType: 'husband',
      applicationNo: '',
    },
  });

  const { register, handleSubmit, watch, setValue, reset } = methods;

  const requiredAffidavitPurposes = prefillTicket ? getTicketAffidavitPurposes(prefillTicket) : [];
  const isAffidavitDateRequired = requiredAffidavitPurposes.length > 0;
  const isTicketOnlyUpdate = prefillMode === 'save_ticket';

  const watchMiscFee = watch('miscFee') ?? 0;
  const watchConsultancyFee = watch('consultancyFee') ?? pricing.marriage_consultancy_fee ?? 500;
  const phoneWatch = watch('phone');
  const watchIsPrimaryContactSpouse = watch('isPrimaryContactSpouse') ?? true;
  const watchContactName = watch('contactName');
  const watchPrimaryContactSpouseType = watch('primaryContactSpouseType');
  const watchMarriageDate = watch('marriageDate');
  const watchAppointmentDate = watch('appointmentDate');
  const watchDateOfService = watch('dateOfService');

  // Hook for Affidavit Linker state
  const linker = useAffidavitLinker({
    setValue,
    phoneWatch,
    watchContactName,
  });

  const {
    selectedAffidavits,
    linkedAffs,
    activeSearchPurpose,
    affSearch,
    showAffDropdown,
    dropdownRef,
    affidavitsResults,
    selectAffidavit,
    unlinkAffidavit,
    linkRequiredAffidavit,
    unlinkRequiredAffidavit,
    startSearch,
    setAffSearch,
    setShowAffDropdown,
    cancelSearch,
    resetLinker,
  } = linker;

  const hasAllAffidavitDates =
    !isAffidavitDateRequired || requiredAffidavitPurposes.every((p) => !!linkedAffs[p]);

  const estimatedAffidavitTotal = useMemo(() => {
    if (!prefillTicket || !prefillTicket.questionnaireData) return 0;
    const q = prefillTicket.questionnaireData;
    let affTotal = 0;
    if (q) {
      const getAmt = (entry: Parameters<typeof getEntryAmount>[0]) => getEntryAmount(entry, pricing);
      if (q.husband) {
        affTotal += getAmt(q.husband.birthDateProof);
        affTotal += getAmt(q.husband.residenceProof);
        affTotal += getAmt(q.husband.identityProof);
      }
      if (q.wife) {
        affTotal += getAmt(q.wife.birthDateProof);
        affTotal += getAmt(q.wife.residenceProof);
        affTotal += getAmt(q.wife.identityProof);
      }
      affTotal += getAmt(q.weddingInvitation);
      affTotal += getAmt(q.firstMarriage);
      affTotal += getAmt(q.intercasteMarriage);
      affTotal += getAmt(q.notRegisteredAnywhereElse);
    }
    return affTotal;
  }, [prefillTicket, pricing]);

  const [includeOfficialFee, setIncludeOfficialFee] = useState(true);
  const [includeCourtFeeTickets, setIncludeCourtFeeTickets] = useState(false);

  // Hook for official fee calculations
  const officialFeeAmount = useOfficialFee({
    marriageDate: watchMarriageDate,
    appointmentDate: watchAppointmentDate,
    dateOfService: watchDateOfService,
    today,
    pricing,
  });

  // Pre-fill from ticket
  useEffect(() => {
    if (prefillTicket) {
      setValue('contactName', prefillTicket.contactName);
      setValue('phone', prefillTicket.phone);
      if (prefillTicket.contactEmail) setValue('contactEmail', prefillTicket.contactEmail);
      if (prefillTicket.address) setValue('address', prefillTicket.address);
      setValue('isPrimaryContactSpouse', prefillTicket.isPrimaryContactSpouse ?? true);
      setValue('primaryContactSpouseType', prefillTicket.primaryContactSpouseType ?? 'husband');

      const ticketSvcs = prefillTicket.servicesProvided || [];
      const includeConsultancy = prefillTicket.questionnaireData?.consultancyFee?.included;
      let finalSvcs =
        includeConsultancy &&
        !ticketSvcs.includes('Marriage Consultancy Fee') &&
        !ticketSvcs.includes('Marriage Registration Consultancy Fee')
          ? [...ticketSvcs, 'Marriage Registration Consultancy Fee']
          : ticketSvcs;

      if (!finalSvcs.includes('Misc (Form - Xerox Copies)')) {
        finalSvcs = [...finalSvcs, 'Misc (Form - Xerox Copies)'];
      }

      setValue('servicesProvided', finalSvcs);
      setValue(
        'miscFee',
        prefillTicket.questionnaireData?.miscFee?.amountCharged ?? pricing.marriage_misc_fee ?? 0,
      );
      setValue(
        'consultancyFee',
        prefillTicket.questionnaireData?.consultancyFee?.amountCharged ??
          pricing.marriage_consultancy_fee ??
          500,
      );
      setValue('ticketId', prefillTicket.id);
      setValue('dateOfService', today);

      setValue('spouse1Name', prefillTicket.questionnaireData?.spouse1Name || '');
      setValue('spouse2Name', prefillTicket.questionnaireData?.spouse2Name || '');
      setValue(
        'marriageAct',
        (prefillTicket.questionnaireData?.marriageAct as MarriageAct) || ('' as unknown as MarriageAct),
      );
      setValue('marriageDate', prefillTicket.questionnaireData?.marriageDate || '');
      setValue('marriagePlace', prefillTicket.questionnaireData?.marriagePlace || '');
      setValue('appointmentDate', prefillTicket.questionnaireData?.appointmentDate || '');
      setValue('affidavitDates', prefillTicket.questionnaireData?.affidavitDates || {});
      setValue('applicationNo', prefillTicket.questionnaireData?.applicationNo || '');

      if (prefillTicket.questionnaireData?.affidavitsPaidSeparately !== undefined) {
        setAffidavitsPaidSeparately(prefillTicket.questionnaireData.affidavitsPaidSeparately);
      } else if (pricing.marriage_affidavits_paid_separately !== undefined) {
        setAffidavitsPaidSeparately(pricing.marriage_affidavits_paid_separately !== 0);
      }
    }
  }, [prefillTicket, setValue, today, pricing]);

  // Sync amountCharged based on affidavitsPaidSeparately toggle
  useEffect(() => {
    if (prefillTicket) {
      const baseVal = Number(prefillTicket.amountCharged);
      const netVal = baseVal - (affidavitsPaidSeparately ? estimatedAffidavitTotal : 0);
      setValue('amountCharged', netVal);
    }
  }, [prefillTicket, affidavitsPaidSeparately, estimatedAffidavitTotal, setValue]);

  // Sync contact details to spouse name dynamically if primary contact is one of the spouses
  useEffect(() => {
    if (watchIsPrimaryContactSpouse) {
      if (watchPrimaryContactSpouseType === 'husband') {
        setValue('spouse1Name', watchContactName || '');
      } else if (watchPrimaryContactSpouseType === 'wife') {
        setValue('spouse2Name', watchContactName || '');
      }
    }
  }, [watchIsPrimaryContactSpouse, watchPrimaryContactSpouseType, watchContactName, setValue]);

  // Customer auto-fill
  const { showAutoFillIndicator, resetIndicator } = useCustomerLookup(
    prefillTicket ? '' : phoneWatch,
    (customer) => {
      setValue('contactName', customer.name);
      if (customer.email) setValue('contactEmail', customer.email);
      if (customer.address) setValue('address', customer.address);
    },
  );

  // Sync amountCharged when services or affidavits change (only for non-ticket forms)
  useEffect(() => {
    if (prefillTicket) return;
    let total = 0;
    const svcs = watch('servicesProvided') || [];
    if (svcs.includes('Online form filling')) total += pricing.online_form;
    if (svcs.includes('Offline form filling')) total += pricing.offline_form;
    if (svcs.includes('Document true copy')) total += pricing.true_copy;
    if (svcs.includes('Misc (Form - Xerox Copies)')) total += Number(watchMiscFee) || 0;
    if (
      svcs.includes('Marriage Consultancy Fee') ||
      svcs.includes('Marriage Registration Consultancy Fee')
    )
      total += Number(watchConsultancyFee) || 0;
    if (includeOfficialFee) total += officialFeeAmount;
    if (includeCourtFeeTickets) total += pricing.marriage_court_fee_tickets ?? 110;
    setValue('amountCharged', total);
  }, [
    watch,
    watchMiscFee,
    watchConsultancyFee,
    pricing,
    setValue,
    prefillTicket,
    includeOfficialFee,
    officialFeeAmount,
    includeCourtFeeTickets,
  ]);

  const saveMutation = useMutation({
    mutationFn: (data: RecordFormValues) => marriagesApi.create(data).then((r) => r.data),
    onSuccess: (data) => {
      qc.invalidateQueries({ queryKey: ['marriages'] });
      qc.invalidateQueries({ queryKey: ['marriage-tickets'] });
      qc.invalidateQueries({ queryKey: ['dashboard'] });
      onSaveSuccess(data);
      resetIndicator();
      reset({
        contactName: '',
        phone: '',
        contactEmail: '',
        address: '',
        isPrimaryContactSpouse: true,
        primaryContactSpouseType: 'husband',
        spouse1Name: '',
        spouse2Name: '',
        marriageAct: '' as unknown as MarriageAct,
        marriageDate: '',
        marriagePlace: '',
        appointmentDate: '',
        affidavitDates: {},
        dateOfService: today,
        servicesProvided: [],
        affidavitIds: [],
        amountCharged: 0,
        miscFee: pricing.marriage_misc_fee ?? 0,
        consultancyFee: pricing.marriage_consultancy_fee ?? 500,
        ticketId: '',
        applicationNo: '',
      });
      resetLinker();
      setAffidavitsPaidSeparately(true);
    },
  });

  const updateTicketMutation = useMutation({
    mutationFn: (payload: { id: string; data: any }) =>
      marriagesApi.updateTicket(payload.id, payload.data).then((r) => r.data),
    onSuccess: (updatedTicket: MarriageTicket) => {
      qc.invalidateQueries({ queryKey: ['marriage-tickets'] });
      if (prefillTicket) {
        qc.invalidateQueries({ queryKey: ['marriage-ticket', prefillTicket.id] });
      }
      resetIndicator();
      reset({
        contactName: '',
        phone: '',
        contactEmail: '',
        address: '',
        isPrimaryContactSpouse: true,
        primaryContactSpouseType: 'husband',
        spouse1Name: '',
        spouse2Name: '',
        marriageAct: '' as unknown as MarriageAct,
        marriageDate: '',
        marriagePlace: '',
        appointmentDate: '',
        affidavitDates: {},
        dateOfService: today,
        servicesProvided: [],
        affidavitIds: [],
        amountCharged: 0,
        miscFee: pricing.marriage_misc_fee ?? 0,
        consultancyFee: pricing.marriage_consultancy_fee ?? 500,
        ticketId: '',
        applicationNo: '',
      });
      resetLinker();
      setAffidavitsPaidSeparately(true);
      onClearPrefill();
      if (onSaveTicketSuccess) {
        onSaveTicketSuccess(updatedTicket);
      }
    },
  });

  return (
    <div className="card" style={{ maxWidth: 680 }}>
      <div style={{ fontWeight: 500, marginBottom: '1rem' }}>
        {prefillTicket
          ? isTicketOnlyUpdate
            ? `Save Ticket State ΓÇö ${prefillTicket.ticketNumber}`
            : `Complete Record ΓÇö ${prefillTicket.ticketNumber}`
          : 'New marriage registration record'}
      </div>

      {saveMutation.isError && (
        <div className="alert-error" style={{ marginBottom: 16 }}>
          Failed to save. Please try again.
        </div>
      )}

      {/* Ticket price breakdown (read-only) */}
      {prefillTicket && (
        <div className="price-box" style={{ marginBottom: 16 }}>
          <div
            style={{ fontWeight: 500, marginBottom: 8, fontSize: 13, color: 'var(--text-muted)' }}
          >
            Estimation breakdown (from ticket)
          </div>
          {(() => {
            const AFFIDAVIT_LABELS = [
              'Husband - Birth Date Proof',
              'Husband - Residence Proof',
              'Husband - Identity Proof',
              'Wife - Birth Date Proof',
              'Wife - Residence Proof',
              'Wife - Identity Proof',
              'Wedding Invitation',
              'First Marriage',
              'Intercaste Marriage',
              'Not Registered Anywhere Else',
            ];

            return getTicketBreakdown(prefillTicket, pricing, servicesDef).map((item, i) => {
              const isAff = AFFIDAVIT_LABELS.some((prefix) => item.label.startsWith(prefix));
              const displayAmt = isAff && affidavitsPaidSeparately ? 0 : item.amount;

              return (
                <div key={i} style={{ marginBottom: 6 }}>
                  <div className="price-row" style={{ marginBottom: 0 }}>
                    <span>{item.label}</span>
                    <span>
                      {isAff && affidavitsPaidSeparately ? (
                        <span style={{ color: 'var(--text-muted)', fontSize: 12, fontWeight: 500 }}>
                          Paid separately
                        </span>
                      ) : (
                        `Γé╣${displayAmt.toLocaleString('en-IN')}`
                      )}
                    </span>
                  </div>
                  {item.remark && (
                    <div
                      style={{
                        fontSize: 11,
                        color: 'var(--danger)',
                        marginTop: 2,
                        paddingLeft: 8,
                        fontWeight: 500,
                      }}
                    >
                      Γå│ Remark: {item.remark}
                    </div>
                  )}
                </div>
              );
            });
          })()}

          {/* Toggle checkbox for separate affidavit billing */}
          {estimatedAffidavitTotal > 0 && (
            <div
              className="checkbox-row"
              style={{
                margin: '12px 0',
                padding: '8px 0',
                borderTop: '1px solid var(--border)',
                borderBottom: '1px solid var(--border)',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
              }}
            >
              <input
                type="checkbox"
                id="f-affidavits-paid-separately"
                checked={affidavitsPaidSeparately}
                onChange={(e) => {
                  const checked = e.target.checked;
                  setAffidavitsPaidSeparately(checked);
                  settingsApi
                    .updateMany({ marriage_affidavits_paid_separately: checked ? 1 : 0 })
                    .then(() => {
                      qc.invalidateQueries({ queryKey: ['pricing-map'] });
                    })
                    .catch((err) => {
                      // eslint-disable-next-line no-console
                      console.error('Failed to save checkbox preference to DB', err);
                    });

                  if (prefillTicket) {
                    marriagesApi
                      .updateTicket(prefillTicket.id, {
                        questionnaireData: {
                          ...prefillTicket.questionnaireData,
                          affidavitsPaidSeparately: checked,
                        },
                      })
                      .then(() => {
                        qc.invalidateQueries({ queryKey: ['marriage-tickets'] });
                      })
                      .catch((err) => {
                        // eslint-disable-next-line no-console
                        console.error('Failed to save ticket preference to DB', err);
                      });
                  }
                }}
                style={{ width: 'auto', margin: 0, cursor: 'pointer' }}
              />
              <label
                htmlFor="f-affidavits-paid-separately"
                style={{
                  margin: 0,
                  fontSize: 13,
                  fontWeight: 600,
                  color: 'var(--text)',
                  cursor: 'pointer',
                }}
              >
                Affidavits executed & paid separately (excludes Γé╣{estimatedAffidavitTotal} from this
                ticket)
              </label>
            </div>
          )}

          <div
            className="price-total"
            style={{ borderBottom: '1px solid var(--border)', paddingBottom: '10px' }}
          >
            <span className="price-total-label">
              {affidavitsPaidSeparately ? 'Marriage Ticket amount' : 'Ticket amount'}
            </span>
            <span className="price-total-value">
              Γé╣
              {(
                Number(prefillTicket.amountCharged) -
                (affidavitsPaidSeparately ? estimatedAffidavitTotal : 0)
              ).toLocaleString('en-IN')}
            </span>
          </div>

          {/* Payment summary & list */}
          {(() => {
            const payments = prefillTicket.payments || [];
            const totalPaid = payments.reduce((sum, p) => sum + Number(p.amount), 0);
            const amountCharged =
              Number(prefillTicket.amountCharged) -
              (affidavitsPaidSeparately ? estimatedAffidavitTotal : 0);
            const balance = amountCharged - totalPaid;

            return (
              <div
                style={{
                  marginTop: '12px',
                  paddingTop: '12px',
                  borderTop: '1px dashed var(--border)',
                }}
              >
                <div
                  style={{ fontWeight: 600, fontSize: 13, marginBottom: 8, color: 'var(--text)' }}
                >
                  Payments & Balance
                </div>
                <div
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    gap: '8px',
                    fontSize: '12px',
                    background: 'var(--bg)',
                    padding: '8px',
                    borderRadius: '4px',
                    marginBottom: '8px',
                    border: '1px solid var(--border)',
                  }}
                >
                  <div>
                    <span style={{ color: 'var(--text-muted)' }}>Paid: </span>
                    <span style={{ fontWeight: 600, color: 'var(--success-text, #15803d)' }}>
                      Γé╣{totalPaid.toLocaleString('en-IN')}
                    </span>
                  </div>
                  <div>
                    <span style={{ color: 'var(--text-muted)' }}>Balance: </span>
                    <span
                      style={{
                        fontWeight: 700,
                        color: balance <= 0 ? 'var(--success-text, #15803d)' : '#dc2626',
                      }}
                    >
                      Γé╣{balance.toLocaleString('en-IN')}
                    </span>
                  </div>
                </div>

                {payments.length > 0 && (
                  <div
                    style={{
                      maxHeight: '100px',
                      overflowY: 'auto',
                      border: '1px solid var(--border)',
                      borderRadius: '4px',
                      fontSize: '11px',
                    }}
                  >
                    <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                      <thead>
                        <tr
                          style={{
                            background: 'var(--bg)',
                            borderBottom: '1px solid var(--border)',
                            textAlign: 'left',
                          }}
                        >
                          <th style={{ padding: '4px 6px' }}>Date</th>
                          <th style={{ padding: '4px 6px' }}>Amt</th>
                          <th style={{ padding: '4px 6px' }}>Mode/Acc</th>
                        </tr>
                      </thead>
                      <tbody>
                        {payments.map((p) => (
                          <tr key={p.id} style={{ borderBottom: '1px solid var(--border)' }}>
                            <td style={{ padding: '4px 6px', whiteSpace: 'nowrap' }}>
                              {new Date(p.paymentDate).toLocaleDateString('en-IN')}
                            </td>
                            <td style={{ padding: '4px 6px', fontWeight: 600 }}>
                              Γé╣{Number(p.amount).toLocaleString('en-IN')}
                            </td>
                            <td style={{ padding: '4px 6px' }}>
                              {p.paymentMode} ({p.account})
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            );
          })()}
        </div>
      )}

      <FormProvider {...methods}>
        <form
          onSubmit={handleSubmit((d) => {
            const isTicketOnlyUpdate = prefillMode === 'save_ticket';

            if (!isTicketOnlyUpdate && requiredAffidavitPurposes.length > 0) {
              const missing = requiredAffidavitPurposes.filter((p) => !linkedAffs[p]);
              if (missing.length > 0) return;
            }

            const officialFee = prefillTicket
              ? prefillTicket.questionnaireData?.officialFee?.included
                ? Number(prefillTicket.questionnaireData?.officialFee?.amountCharged || 0)
                : 0
              : includeOfficialFee
                ? officialFeeAmount
                : 0;

            const courtFeeTickets = prefillTicket
              ? prefillTicket.questionnaireData?.courtFeeTickets?.included
                ? Number(prefillTicket.questionnaireData?.courtFeeTickets?.amountCharged || 0)
                : 0
              : includeCourtFeeTickets
                ? (pricing.marriage_court_fee_tickets ?? 110)
                : 0;

            const miscFee = prefillTicket
              ? prefillTicket.questionnaireData?.miscFee?.included
                ? Number(prefillTicket.questionnaireData?.miscFee?.amountCharged || 0)
                : 0
              : d.servicesProvided?.includes('Misc (Form - Xerox Copies)')
                ? Number(d.miscFee || 0)
                : 0;

            const consultancyFee = prefillTicket
              ? prefillTicket.questionnaireData?.consultancyFee?.included
                ? Number(prefillTicket.questionnaireData?.consultancyFee?.amountCharged || 0)
                : 0
              : d.servicesProvided?.includes('Marriage Registration Consultancy Fee') ||
                  d.servicesProvided?.includes('Marriage Consultancy Fee')
                ? Number(d.consultancyFee || 0)
                : 0;

            if (isTicketOnlyUpdate && prefillTicket) {
              const ticketPayload = {
                contactName: d.contactName,
                phone: d.phone,
                contactEmail: d.contactEmail || undefined,
                address: d.address || undefined,
                isPrimaryContactSpouse: d.isPrimaryContactSpouse,
                primaryContactSpouseType: d.isPrimaryContactSpouse
                  ? d.primaryContactSpouseType
                  : null,
                servicesProvided: d.servicesProvided,
                amountCharged: Number(prefillTicket.amountCharged), // Keep original estimated total!
                questionnaireData: {
                  ...prefillTicket.questionnaireData,
                  spouse1Name: d.spouse1Name,
                  spouse2Name: d.spouse2Name,
                  marriageAct: d.marriageAct,
                  marriageDate: d.marriageDate,
                  marriagePlace: d.marriagePlace,
                  appointmentDate: d.appointmentDate,
                  affidavitDates: d.affidavitDates,
                  applicationNo: d.applicationNo,
                  officialFee: {
                    ...prefillTicket.questionnaireData?.officialFee,
                    amountCharged: officialFee,
                  },
                  courtFeeTickets: {
                    ...prefillTicket.questionnaireData?.courtFeeTickets,
                    amountCharged: courtFeeTickets,
                  },
                  miscFee: {
                    ...prefillTicket.questionnaireData?.miscFee,
                    amountCharged: miscFee,
                  },
                  consultancyFee: {
                    ...prefillTicket.questionnaireData?.consultancyFee,
                    amountCharged: consultancyFee,
                  },
                },
              };
              updateTicketMutation.mutate({ id: prefillTicket.id, data: ticketPayload });
            } else {
              const payload = {
                ...d,
                contactEmail: d.contactEmail || undefined,
                officialFee,
                courtFeeTickets,
                miscFee,
                consultancyFee,
                affidavitIds: prefillTicket
                  ? Object.values(linkedAffs).map((x) => x.id)
                  : selectedAffidavits.map((x) => x.id),
              };
              saveMutation.mutate(payload);
            }
          })}
        >
          {/* Customer / Contact details */}
          <CustomerSection showAutoFillIndicator={showAutoFillIndicator} />

          {/* Marriage details */}
          <MarriageDetailsSection today={today} />

          {/* Linked Affidavits list / link inputs */}
          <AffidavitListSection
            prefillTicket={prefillTicket}
            requiredAffidavitPurposes={requiredAffidavitPurposes}
            linkedAffs={linkedAffs}
            activeSearchPurpose={activeSearchPurpose}
            affSearch={affSearch}
            showAffDropdown={showAffDropdown}
            affidavitsResults={affidavitsResults}
            selectedAffidavits={selectedAffidavits}
            dropdownRef={dropdownRef}
            selectAffidavit={selectAffidavit}
            unlinkAffidavit={unlinkAffidavit}
            linkRequiredAffidavit={linkRequiredAffidavit}
            unlinkRequiredAffidavit={unlinkRequiredAffidavit}
            startSearch={startSearch}
            setAffSearch={setAffSearch}
            setShowAffDropdown={setShowAffDropdown}
            cancelSearch={cancelSearch}
          />

          {/* Services selections (only when no prefilled ticket is active) */}
          {!prefillTicket && (
            <ServicesSection
              servicesDef={servicesDef}
              pricing={pricing}
              officialFeeAmount={officialFeeAmount}
              watchMarriageDate={watchMarriageDate}
              includeOfficialFee={includeOfficialFee}
              setIncludeOfficialFee={setIncludeOfficialFee}
              includeCourtFeeTickets={includeCourtFeeTickets}
              setIncludeCourtFeeTickets={setIncludeCourtFeeTickets}
            />
          )}

          <div className="form-group" style={{ marginTop: 16 }}>
            <label>Amount charged (Γé╣) *</label>
            <input
              type="number"
              {...register('amountCharged', { required: true, min: 0, valueAsNumber: true })}
              placeholder="Auto-calculated, can edit"
            />
          </div>

          <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
            <button
              className="btn btn-primary"
              type="submit"
              disabled={
                saveMutation.isPending ||
                updateTicketMutation.isPending ||
                (!isTicketOnlyUpdate && !hasAllAffidavitDates)
              }
            >
              {saveMutation.isPending || updateTicketMutation.isPending
                ? 'SavingΓÇª'
                : isTicketOnlyUpdate
                  ? 'Save Ticket State'
                  : 'Save record'}
            </button>
            <button
              type="button"
              className="btn"
              onClick={() => {
                reset({
                  contactName: '',
                  phone: '',
                  contactEmail: '',
                  address: '',
                  isPrimaryContactSpouse: true,
                  primaryContactSpouseType: 'husband',
                  spouse1Name: '',
                  spouse2Name: '',
                  marriageAct: '' as unknown as MarriageAct,
                  marriageDate: '',
                  marriagePlace: '',
                  appointmentDate: '',
                  affidavitDates: {},
                  dateOfService: today,
                  servicesProvided: ['Misc (Form - Xerox Copies)'],
                  affidavitIds: [],
                  amountCharged: 0,
                  miscFee: pricing.marriage_misc_fee ?? 0,
                  consultancyFee: pricing.marriage_consultancy_fee ?? 500,
                  ticketId: '',
                  applicationNo: '',
                });
                resetLinker();
                resetIndicator();
                onClearPrefill();
              }}
            >
              Clear
            </button>
          </div>
        </form>
      </FormProvider>
    </div>
  );
}

import { useMemo, useEffect } from 'react';
import { PaperType, AuthorizerType } from '@/types';
import { calcAffidavitTotal } from '@/hooks/usePricing';
import NeoSelect from '@/components/NeoSelect';

interface SituationBlockProps {
  label: string;
  radioLabel: [string, string];
  entry: {
    yes?: boolean;
    available?: boolean;
    affidavit?: string;
    paperType?: PaperType;
    authorizer?: AuthorizerType;
    amountCharged?: number;
    remark?: string;
    customerName?: string;
    customerBroughtStamp?: boolean;
  };
  triggerOnValue: boolean;
  onChange: (updated: any) => void;
  pricing: Record<string, number>;
  showNameInput?: boolean;
  nameInputLabel?: string;
}

export default function SituationBlock({
  label,
  radioLabel,
  entry,
  triggerOnValue,
  onChange,
  pricing,
  showNameInput,
  nameInputLabel = 'Affidavit Name *',
}: SituationBlockProps) {
  const currentVal = entry.yes !== undefined ? entry.yes : entry.available;
  const needsAffidavit = currentVal === triggerOnValue;
  const affYes = entry.affidavit === 'Yes';
  const fieldKey = entry.yes !== undefined ? 'yes' : 'available';

  const calcAmount = useMemo(() => {
    if (!affYes || !entry.paperType || !entry.authorizer) return 0;
    const res = calcAffidavitTotal(entry.paperType, entry.authorizer, pricing);
    if (entry.paperType === 'stamp500' && entry.customerBroughtStamp === true) {
      return res.authFee;
    }
    return res.total;
  }, [affYes, entry.paperType, entry.authorizer, entry.customerBroughtStamp, pricing]);

  const isDiscounted =
    affYes &&
    !!entry.paperType &&
    !!entry.authorizer &&
    entry.amountCharged !== undefined &&
    entry.amountCharged < calcAmount;

  useEffect(() => {
    if (!isDiscounted && entry.remark) {
      onChange({ ...entry, remark: undefined });
    }
  }, [isDiscounted, entry.remark, entry, onChange]);

  return (
    <div
      style={{
        marginBottom: 16,
        padding: '12px 14px',
        border: '1px solid var(--border)',
        borderRadius: 8,
        background: 'var(--bg)',
      }}
    >
      <div style={{ fontWeight: 500, marginBottom: 8, fontSize: 14 }}>{label}</div>
      <div
        style={{
          display: 'flex',
          gap: 16,
          alignItems: 'center',
          marginBottom: needsAffidavit ? 10 : 0,
        }}
      >
        <label
          style={{ display: 'flex', gap: 6, alignItems: 'center', fontSize: 13, cursor: 'pointer' }}
        >
          <input
            type="radio"
            checked={currentVal === true}
            onChange={() => onChange({ [fieldKey]: true, affidavit: 'No' })}
          />
          {radioLabel[0]}
        </label>
        <label
          style={{ display: 'flex', gap: 6, alignItems: 'center', fontSize: 13, cursor: 'pointer' }}
        >
          <input
            type="radio"
            checked={currentVal === false}
            onChange={() => onChange({ [fieldKey]: false, affidavit: 'No' })}
          />
          {radioLabel[1]}
        </label>
      </div>

      {needsAffidavit && (
        <>
          <div className="form-group" style={{ marginBottom: 8 }}>
            <label style={{ fontSize: 12 }}>Need affidavit?</label>
            <NeoSelect
              value={entry.affidavit || 'No'}
              onChange={(val) =>
                onChange({
                  ...entry,
                  affidavit: val,
                  paperType: undefined,
                  authorizer: undefined,
                  amountCharged: undefined,
                  customerName: undefined,
                  customerBroughtStamp: undefined,
                })
              }
              options={[
                { value: 'No', label: 'No' },
                { value: 'Yes', label: 'Yes' },
                { value: 'Combined with other', label: 'Combined with other' },
              ]}
            />
          </div>

          {affYes && (
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 8 }}>
              {showNameInput && (
                <div className="form-group" style={{ gridColumn: 'span 3', marginBottom: 8 }}>
                  <label style={{ fontSize: 12 }}>{nameInputLabel}</label>
                  <input
                    type="text"
                    value={entry.customerName || ''}
                    onChange={(e) => onChange({ ...entry, customerName: e.target.value })}
                    placeholder="Enter name for affidavit"
                    style={{ fontSize: 13 }}
                  />
                  {!entry.customerName?.trim() && (
                    <span
                      style={{
                        color: 'var(--danger)',
                        fontSize: 11,
                        display: 'block',
                        marginTop: 4,
                      }}
                    >
                      ΓÜá Name is required for this affidavit.
                    </span>
                  )}
                </div>
              )}
              <div className="form-group" style={{ marginBottom: 0 }}>
                <label style={{ fontSize: 12 }}>Paper type</label>
                <NeoSelect
                  value={entry.paperType || ''}
                  onChange={(val) => {
                    const pt = val as PaperType;
                    const res = calcAffidavitTotal(pt, entry.authorizer || 'magistrate', pricing);
                    onChange({
                      ...entry,
                      paperType: pt,
                      customerBroughtStamp: pt === 'stamp500' ? false : undefined,
                      amountCharged: res.total,
                    });
                  }}
                  options={[
                    { value: 'stamp500', label: 'Γé╣500 Stamp Paper' },
                    { value: 'Plain', label: 'Plain Paper' },
                  ]}
                  placeholder="Select"
                />
              </div>
              <div className="form-group" style={{ marginBottom: 0 }}>
                <label style={{ fontSize: 12 }}>Authorizer</label>
                <NeoSelect
                  value={entry.authorizer || ''}
                  onChange={(val) => {
                    const auth = val as AuthorizerType;
                    const res = calcAffidavitTotal(entry.paperType || 'stamp500', auth, pricing);
                    const newCalc =
                      entry.paperType === 'stamp500' && entry.customerBroughtStamp === true
                        ? res.authFee
                        : res.total;
                    onChange({ ...entry, authorizer: auth, amountCharged: newCalc });
                  }}
                  options={[
                    { value: 'magistrate', label: 'Executive Magistrate' },
                    { value: 'Notary', label: 'Notary Public' },
                  ]}
                  placeholder="Select"
                />
              </div>
              <div className="form-group" style={{ marginBottom: 0 }}>
                <label style={{ fontSize: 12 }}>Amount (Γé╣)</label>
                <input
                  type="number"
                  min={0}
                  value={entry.amountCharged ?? calcAmount}
                  onChange={(e) => onChange({ ...entry, amountCharged: Number(e.target.value) })}
                  style={{ fontSize: 13 }}
                />
              </div>
              {entry.paperType === 'stamp500' && (
                <div
                  className="form-group"
                  style={{ gridColumn: 'span 3', marginTop: 8, marginBottom: 0 }}
                >
                  <label style={{ fontSize: 12 }}>Stamp? *</label>
                  <div style={{ display: 'flex', gap: 20, marginTop: 4 }}>
                    <label
                      style={{
                        display: 'flex',
                        gap: 6,
                        alignItems: 'center',
                        cursor: 'pointer',
                        fontSize: 13,
                      }}
                    >
                      <input
                        type="radio"
                        checked={entry.customerBroughtStamp === true}
                        onChange={() => {
                          const res = calcAffidavitTotal(
                            entry.paperType || 'stamp500',
                            entry.authorizer || 'magistrate',
                            pricing,
                          );
                          onChange({
                            ...entry,
                            customerBroughtStamp: true,
                            amountCharged: res.authFee,
                          });
                        }}
                      />
                      Without Stamp
                    </label>
                    <label
                      style={{
                        display: 'flex',
                        gap: 6,
                        alignItems: 'center',
                        cursor: 'pointer',
                        fontSize: 13,
                      }}
                    >
                      <input
                        type="radio"
                        checked={entry.customerBroughtStamp !== true}
                        onChange={() => {
                          const res = calcAffidavitTotal(
                            entry.paperType || 'stamp500',
                            entry.authorizer || 'magistrate',
                            pricing,
                          );
                          onChange({
                            ...entry,
                            customerBroughtStamp: false,
                            amountCharged: res.total,
                          });
                        }}
                      />
                      With Stamp
                    </label>
                  </div>
                </div>
              )}
              {isDiscounted && (
                <div
                  className="form-group"
                  style={{ gridColumn: 'span 3', marginTop: 8, marginBottom: 0 }}
                >
                  <label style={{ fontSize: 12 }}>Remark (Reason for discount) *</label>
                  <input
                    type="text"
                    value={entry.remark || ''}
                    onChange={(e) => onChange({ ...entry, remark: e.target.value })}
                    placeholder="Reason for charging less than standard rate"
                    style={{ fontSize: 13 }}
                  />
                </div>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { MarriageTicket } from '@/types';
import { PAYMENT_MODES } from '@/constants';
import { usePaymentAccounts } from '@/hooks/usePaymentAccounts';
import { marriagesApi, settingsApi } from '@/api';
import { useAuth } from '@/context/AuthContext';
import { getTicketBreakdown, getEntryAmount } from './helpers';
import NeoSelect from '@/components/NeoSelect';
import NeoDatePicker from '@/components/NeoDatePicker';
import UpiQrCode from '@/components/UpiQrCode';

interface TicketDetailsModalProps {
  ticket: MarriageTicket;
  pricing: Record<string, number>;
  servicesDef: { key: string; cost: number }[];
  onClose: () => void;
  onProceed?: (ticket: MarriageTicket) => void;
  onEdit?: (ticket: MarriageTicket) => void;
  onShowAlert?: (title: string, message: React.ReactNode) => void;
  onShowConfirm?: (title: string, message: React.ReactNode, onConfirm: () => void) => void;
}

export default function TicketDetailsModal({
  ticket: initialTicket,
  pricing,
  servicesDef,
  onClose,
  onProceed,
  onEdit,
  onShowAlert,
  onShowConfirm,
}: TicketDetailsModalProps) {
  const qc = useQueryClient();
  const { isAdmin } = useAuth();

  // Freshly fetch the ticket with its payments relations
  const { data: ticket = initialTicket } = useQuery({
    queryKey: ['marriage-ticket', initialTicket.id],
    queryFn: () => marriagesApi.getTicketById(initialTicket.id).then((r) => r.data),
    initialData: initialTicket,
    staleTime: 5000,
  });

  // State for adding a payment
  const [showAddForm, setShowAddForm] = useState(false);
  const [amount, setAmount] = useState('');
  const {
    paymentMode,
    setPaymentMode,
    selectedAccount,
    setSelectedAccount,
    customAccount,
    setCustomAccount,
    isOtherSelected,
    accountOptions,
    resolvedAccount,
    reset: resetAccounts,
  } = usePaymentAccounts();
  const [paymentDate, setPaymentDate] = useState(new Date().toISOString().split('T')[0]);
  const [notes, setNotes] = useState('');
  const [error, setError] = useState('');
  const [upiId, setUpiId] = useState('');
  const [payeeName, setPayeeName] = useState('');

  useEffect(() => {
    if (paymentMode === 'UPI') {
      const lower = (selectedAccount || '').toLowerCase();
      if (lower.includes('vaishali')) {
        setUpiId(import.meta.env.VITE_UPI_ID_VAISHALI || '9890692659@upi');
        setPayeeName('Vaishali Gurav');
      } else if (lower.includes('ashish')) {
        setUpiId(import.meta.env.VITE_UPI_ID_ASHISH || '9112019559@upi');
        setPayeeName('Ashish Gurav');
      } else if (lower.includes('parshuram')) {
        setUpiId(import.meta.env.VITE_UPI_ID_PARSHURAM || '9372725588@upi');
        setPayeeName('Parshuram Gurav');
      } else if (lower.includes('gauri')) {
        setUpiId(import.meta.env.VITE_UPI_ID_GAURI || '7066115942@barodampay');
        setPayeeName('Gauri Gurav');
      } else if (selectedAccount === 'Other') {
        setPayeeName(customAccount || 'Gurav Online Services');
      }
    } else {
      setUpiId('');
      setPayeeName('');
    }
  }, [paymentMode, selectedAccount, customAccount]);

  // Mutations
  const addPaymentMut = useMutation({
    mutationFn: (data: any) => marriagesApi.addPayment(data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['marriage-ticket', ticket.id] });
      qc.invalidateQueries({ queryKey: ['marriage-tickets'] });
      // Reset form
      setAmount('');
      resetAccounts();
      setPaymentDate(new Date().toISOString().split('T')[0]);
      setNotes('');
      setError('');
      setShowAddForm(false);
    },
  });

  const deletePaymentMut = useMutation({
    mutationFn: (id: string) => marriagesApi.deletePayment(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['marriage-ticket', ticket.id] });
      qc.invalidateQueries({ queryKey: ['marriage-tickets'] });
    },
  });

  const failTicketMut = useMutation({
    mutationFn: () => marriagesApi.failTicket(ticket.id).then((r) => r.data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['marriage-tickets'] });
      qc.invalidateQueries({ queryKey: ['marriage-ticket', ticket.id] });
      onClose();
    },
    onError: () => {
      alert('Failed to mark ticket as failed.');
    },
  });

  const [affidavitsPaidSeparately, setAffidavitsPaidSeparately] = useState(() => {
    if (ticket?.questionnaireData?.affidavitsPaidSeparately !== undefined) {
      return ticket.questionnaireData.affidavitsPaidSeparately;
    }
    return pricing.marriage_affidavits_paid_separately !== 0;
  });

  useEffect(() => {
    if (ticket?.questionnaireData?.affidavitsPaidSeparately !== undefined) {
      setAffidavitsPaidSeparately(ticket.questionnaireData.affidavitsPaidSeparately);
    } else if (pricing.marriage_affidavits_paid_separately !== undefined) {
      setAffidavitsPaidSeparately(pricing.marriage_affidavits_paid_separately !== 0);
    }
  }, [
    ticket?.questionnaireData?.affidavitsPaidSeparately,
    pricing.marriage_affidavits_paid_separately,
  ]);

  const estimatedAffidavitTotal = useMemo(() => {
    if (!ticket || !ticket.questionnaireData) return 0;
    const q = ticket.questionnaireData;
    let affTotal = 0;
    if (q) {
      const getAmt = (entry: any) => getEntryAmount(entry, pricing);
      if (q.husband) {
        affTotal += getAmt(q.husband.birthDateProof);
        affTotal += getAmt(q.husband.residenceProof);
        affTotal += getAmt(q.husband.identityProof);
      }
      if (q.wife) {
        affTotal += getAmt(q.wife.birthDateProof);
        affTotal += getAmt(q.wife.residenceProof);
        affTotal += getAmt(q.wife.identityProof);
      }
      affTotal += getAmt(q.weddingInvitation);
      affTotal += getAmt(q.firstMarriage);
      affTotal += getAmt(q.intercasteMarriage);
      affTotal += getAmt(q.notRegisteredAnywhereElse);
    }
    return affTotal;
  }, [ticket, pricing]);

  // Computations
  const payments = ticket.payments || [];
  const totalPaid = payments.reduce((sum, p) => sum + Number(p.amount), 0);
  const amountCharged =
    Number(ticket.amountCharged) - (affidavitsPaidSeparately ? estimatedAffidavitTotal : 0);
  const balance = amountCharged - totalPaid;

  const handleAddPaymentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const amtVal = parseFloat(amount);
    if (isNaN(amtVal) || amtVal <= 0) {
      setError('Please enter a valid payment amount greater than zero.');
      return;
    }
    if (!paymentMode) {
      setError('Please select a payment mode.');
      return;
    }
    if (!selectedAccount) {
      setError('Please select a target account.');
      return;
    }
    if (isOtherSelected && !customAccount.trim()) {
      setError('Please specify the other account name.');
      return;
    }
    if (!paymentDate) {
      setError('Please select a payment date.');
      return;
    }

    addPaymentMut.mutate({
      amount: amtVal,
      paymentMode,
      account: resolvedAccount,
      paymentDate,
      notes: notes.trim() || undefined,
      ticketId: ticket.id,
    });
  };

  const handleDeletePayment = (paymentId: string) => {
    if (window.confirm('Are you sure you want to delete this payment? This action is permanent.')) {
      deletePaymentMut.mutate(paymentId);
    }
  };

  const modeOptions = PAYMENT_MODES.map((m) => ({ value: m, label: m }));

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(0,0,0,0.4)',
        zIndex: 1000,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '1rem',
      }}
    >
      <div
        className="card modal-card"
        style={{
          width: '100%',
          maxWidth: 540,
          position: 'relative',
          padding: 0,
          maxHeight: '90vh',
          display: 'flex',
          flexDirection: 'column',
          overflow: 'hidden',
        }}
      >
        <button
          onClick={onClose}
          style={{
            position: 'absolute',
            top: '1rem',
            right: '1.5rem',
            background: 'none',
            border: 'none',
            fontSize: 18,
            cursor: 'pointer',
            color: 'var(--text-muted)',
            zIndex: 10,
          }}
        >
          Γ£ò
        </button>
        <div
          style={{
            overflowY: 'auto',
            padding: '1.5rem 2rem',
            flex: 1,
            display: 'flex',
            flexDirection: 'column',
          }}
        >
          <h3
            style={{ fontSize: 18, fontWeight: 700, marginBottom: '1.5rem', textAlign: 'center' }}
          >
            Ticket Details ΓÇö {ticket.ticketNumber}
          </h3>

          {/* Customer Information Grid */}
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: '1fr 1fr',
              gap: '12px 16px',
              marginBottom: '1.5rem',
              fontSize: '13px',
            }}
          >
            <div>
              <span style={{ color: 'var(--text-muted)', display: 'block' }}>Customer Name</span>
              <span style={{ fontWeight: 500 }}>{ticket.contactName}</span>
