              <span style={{ color: 'var(--text-muted)', display: 'block' }}>
                Primary Contact Type
              </span>
              <span style={{ fontWeight: 500 }}>
                {(ticket.isPrimaryContactSpouse ?? true)
                  ? `One of the Spouses (${ticket.primaryContactSpouseType === 'wife' ? 'Wife' : 'Husband'})`
