              >
                {ticket.status}
              </span>
            </div>
          </div>

          {/* Estimation Breakdown */}
          <div className="price-box" style={{ marginBottom: 20 }}>
            <div
              style={{ fontWeight: 500, marginBottom: 8, fontSize: 13, color: 'var(--text-muted)' }}
