                      </span>
                    </div>
                    {item.remark && (
                      <div
                        style={{
                          fontSize: 11,
                          color: 'var(--danger)',
                          marginTop: 2,
                          paddingLeft: 8,
                          fontWeight: 500,
                        }}
                      >
                        Γå│ Remark: {item.remark}
                      </div>
                    )}
                  </div>
                );
              });
            })()}

            {/* Toggle checkbox for separate affidavit billing */}
            {estimatedAffidavitTotal > 0 && (
              <div
