              <span className="price-total-label">
                {affidavitsPaidSeparately ? 'Marriage Ticket amount' : 'Total Amount Charged'}
              </span>
              <span className="price-total-value">Γé╣{amountCharged.toLocaleString('en-IN')}</span>
