              {/* Summary Bar */}
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  gap: '8px',
                  fontSize: '13px',
                  background: 'var(--bg)',
                  padding: '10px',
                  borderRadius: '4px',
                  marginBottom: '12px',
                  border: '1px solid var(--border)',
                }}
              >
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Charged: </span>
                  <span style={{ fontWeight: 600 }}>Γé╣{amountCharged.toLocaleString('en-IN')}</span>
                </div>
                <div>
                  <span style={{ color: 'var(--text-muted)' }}>Paid: </span>
