              {/* Payment History List */}
              {payments.length === 0 ? (
                <div
                  style={{
                    fontSize: '12px',
                    color: 'var(--text-muted)',
                    textAlign: 'center',
                    padding: '8px 0',
                    fontStyle: 'italic',
