                              required
                            />
                          </div>
                        )}

                        {paymentMode === 'UPI' && (
                          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                            {selectedAccount === 'Other' && (
                              <div>
                                <label
                                  style={{
                                    display: 'block',
                                    fontSize: '11px',
                                    fontWeight: 600,
                                    marginBottom: '4px',
                                  }}
                                >
                                  Payee Name *
                                </label>
                                <input
                                  type="text"
                                  value={payeeName}
                                  onChange={(e) => setPayeeName(e.target.value)}
                                  placeholder="e.g. Gurav Online Services"
                                  style={{
                                    width: '100%',
                                    padding: '6px 8px',
                                    border: '1.5px solid var(--border)',
                                    borderRadius: '4px',
                                    fontSize: '12px',
                                  }}
                                  required
                                />
                              </div>
                            )}
                            <div>
                              <label
                                style={{
                                  display: 'block',
                                  fontSize: '11px',
                                  fontWeight: 600,
                                  marginBottom: '4px',
                                }}
                              >
                                Payee UPI ID *
                              </label>
                              <input
                                type="text"
                                value={upiId}
                                onChange={(e) => setUpiId(e.target.value)}
                                placeholder="e.g. merchant@okaxis"
                                style={{
                                  width: '100%',
                                  padding: '6px 8px',
                                  border: '1.5px solid var(--border)',
                                  borderRadius: '4px',
                                  fontSize: '12px',
                                }}
                                required
                              />
                            </div>

                            <UpiQrCode
                              upiId={upiId}
                              payeeName={payeeName}
                              amount={parseFloat(amount) || 0}
                              transactionRef={`${ticket.ticketNumber}-${Date.now()}`}
                              transactionNote={`Payment for Marriage Ticket ${ticket.ticketNumber}`}
                            />
                          </div>
                        )}

                        <div>
                          <label
                            style={{
                              display: 'block',
                              fontSize: '11px',
                              fontWeight: 600,
                              marginBottom: '4px',
                            }}
                          >
                            Payment Date *
                          </label>
                          <NeoDatePicker
                            value={paymentDate}
                            onChange={setPaymentDate}
                            style={{ height: '32px' }}
                          />
                        </div>

                        <div>
                          <label
                            style={{
                              display: 'block',
                              fontSize: '11px',
                              fontWeight: 600,
                              marginBottom: '4px',
                            }}
                          >
                            Notes
                          </label>
                          <input
                            type="text"
                            value={notes}
                            onChange={(e) => setNotes(e.target.value)}
                            placeholder="Remarks"
                            style={{
                              width: '100%',
                              padding: '6px 8px',
                              border: '1.5px solid var(--border)',
                              borderRadius: '4px',
                              fontSize: '12px',
                            }}
                          />
                        </div>

                        {error && (
                          <div
                            style={{ color: 'var(--danger)', fontSize: '11px', fontWeight: 500 }}
                          >
                            ΓÜá∩╕Å {error}
                          </div>
                        )}

                        <div
                          style={{
                            display: 'flex',
                            gap: '8px',
                            justifyContent: 'flex-end',
                            marginTop: '6px',
                          }}
                        >
                          <button
                            type="button"
                            className="btn btn-sm btn-secondary"
                            onClick={() => {
                              setShowAddForm(false);
                              setError('');
                            }}
