              ))}
            </tbody>
          </table>
        </div>
      )}

      {confirmingTicket && (
        <ConfirmTicketModal
          ticket={confirmingTicket}
          onClose={() => setConfirmingTicket(null)}
          onConfirm={(payment) => {
            confirmTicketMut.mutate({ id: confirmingTicket.id, payment });
          }}
          isLoading={confirmTicketMut.isPending}
        />
      )}
    </div>
  );
}

import { PaperType, AuthorizerType, QuestionnaireData, ProofEntry, MarriageTicket } from '@/types';
import { calcAffidavitTotal } from '@/hooks/usePricing';

export function defaultProof(): ProofEntry {
  return { correct: true };
}

export function defaultQuestionnaire(): QuestionnaireData {
  return {
    husband: {
      birthDateProof: defaultProof(),
      residenceProof: defaultProof(),
      identityProof: defaultProof(),
    },
    wife: {
      birthDateProof: defaultProof(),
      residenceProof: defaultProof(),
      identityProof: defaultProof(),
    },
    weddingInvitation: { available: true, affidavit: 'No' },
    firstMarriage: { yes: true, affidavit: 'No' },
    intercasteMarriage: { yes: false, affidavit: 'No' },
    notRegisteredAnywhereElse: {
      yes: true,
      affidavit: 'Yes',
      paperType: 'stamp500',
      authorizer: 'magistrate',
      customerBroughtStamp: false,
    },
    consultancyFee: { included: false, amountCharged: 0 },
    officialFee: { included: false, duration: 'Upto 3 months', amountCharged: 0 },
    courtFeeTickets: { included: false, amountCharged: 0 },
  };
}

export function getEntryAmount(
  entry?: {
    affidavit?: string;
    amountCharged?: number;
    paperType?: PaperType;
    authorizer?: AuthorizerType;
    customerBroughtStamp?: boolean;
  },
  pricing?: Record<string, number>,
): number {
  if (!entry || entry.affidavit !== 'Yes') return 0;
  if (entry.amountCharged !== undefined) return entry.amountCharged;
  if (entry.paperType && entry.authorizer && pricing) {
    const res = calcAffidavitTotal(entry.paperType, entry.authorizer, pricing);
    if (entry.paperType === 'stamp500' && entry.customerBroughtStamp === true) {
      return res.authFee;
    }
    return res.total;
  }
  return 0;
}

export function calcEstimationTotal(
  q: QuestionnaireData,
  services: string[],
  pricing: Record<string, number>,
): number {
  let total = 0;

  // Husband
  total += getEntryAmount(q.husband?.birthDateProof, pricing);
  total += getEntryAmount(q.husband?.residenceProof, pricing);
  total += getEntryAmount(q.husband?.identityProof, pricing);

  // Wife
  total += getEntryAmount(q.wife?.birthDateProof, pricing);
  total += getEntryAmount(q.wife?.residenceProof, pricing);
  total += getEntryAmount(q.wife?.identityProof, pricing);

  // Misc
  total += getEntryAmount(q.weddingInvitation, pricing);
  total += getEntryAmount(q.firstMarriage, pricing);
  total += getEntryAmount(q.intercasteMarriage, pricing);
  total += getEntryAmount(q.notRegisteredAnywhereElse, pricing);

  // Consultancy Fee
  if (q.consultancyFee?.included) {
    total += q.consultancyFee?.amountCharged ?? pricing.marriage_consultancy_fee ?? 500;
  }

  // Official Fee
  if (q.officialFee?.included) {
    if (
      q.officialFee.amountCharged !== undefined &&
      q.officialFee.amountCharged !== null &&
      q.officialFee.amountCharged > 0
    ) {
      total += q.officialFee.amountCharged;
    } else {
      if (q.officialFee.duration === 'Upto 3 months')
        total += pricing.marriage_official_fee_upto_3_months ?? 500;
      else if (q.officialFee.duration === '3 - 12 months')
        total += pricing.marriage_official_fee_3_to_12_months ?? 600;
      else if (q.officialFee.duration === 'After 12 months')
        total += pricing.marriage_official_fee_after_12_months ?? 750;
    }
  }

  // Court Fee Tickets
  if (q.courtFeeTickets?.included) {
    const courtFeeAmt = q.courtFeeTickets?.amountCharged;
    total +=
      courtFeeAmt !== undefined && courtFeeAmt !== null && courtFeeAmt > 0
        ? courtFeeAmt
        : (pricing.marriage_court_fee_tickets ?? 110);
  }

  // Services
  if (services.includes('Online form filling')) total += pricing.online_form ?? 0;
  if (services.includes('Offline form filling')) total += pricing.offline_form ?? 0;
  if (services.includes('Document true copy')) total += pricing.true_copy ?? 0;
  if (services.includes('Misc (Form - Xerox Copies)')) {
    total +=
      q.miscFee?.amountCharged !== undefined
        ? q.miscFee.amountCharged
        : (pricing.marriage_misc_fee ?? 0);
  }

  return total;
}

export function getTicketAffidavitPurposes(ticket: MarriageTicket): string[] {
  const q = ticket.questionnaireData;
  if (!q) return [];
  const purposes: string[] = [];

  const checkProof = (entry: any, purpose: string) => {
    if (entry && entry.correct === false && entry.affidavit === 'Yes') purposes.push(purpose);
  };

  const checkSituation = (entry: any, triggerOnValue: boolean, purpose: string) => {
    if (!entry || entry.affidavit !== 'Yes') return;
    const currentVal = entry.yes !== undefined ? entry.yes : entry.available;
    if (currentVal === triggerOnValue) purposes.push(purpose);
  };

  if (q.husband) {
    checkProof(q.husband.birthDateProof, 'Husband - Birth Date Proof Correction');
    checkProof(q.husband.residenceProof, 'Husband - Residence Proof Correction');
    checkProof(q.husband.identityProof, 'Husband - Identity Proof Correction');
  }
  if (q.wife) {
    checkProof(q.wife.birthDateProof, 'Wife - Birth Date Proof Correction');
    checkProof(q.wife.residenceProof, 'Wife - Residence Proof Correction');
    checkProof(q.wife.identityProof, 'Wife - Identity Proof Correction');
  }
  checkSituation(q.weddingInvitation, false, 'Wedding Invitation Affidavit');
  checkSituation(q.firstMarriage, false, 'Subsequent Marriage Affidavit');
  checkSituation(q.intercasteMarriage, true, 'Intercaste Marriage Affidavit');
  checkSituation(q.notRegisteredAnywhereElse, true, 'Not Registered Anywhere Else Affidavit');

  return purposes;
}

export function getTicketBreakdown(
  ticket: MarriageTicket,
  pricing: Record<string, number>,
  servicesDef: { key: string; cost: number }[],
) {
  const items: { label: string; amount: number; remark?: string }[] = [];
  const q = ticket.questionnaireData;
  if (!q) {
    (ticket.servicesProvided || []).forEach((svc) => {
      const svcDef = servicesDef.find((s) => s.key === svc);
      if (svcDef) items.push({ label: svc, amount: svcDef.cost });
    });
    return items;
  }
  const addEntry = (label: string, entry?: any) => {
    const amt = getEntryAmount(entry, pricing);
    if (amt > 0) {
      let finalLabel = label;
      if (entry?.customerName?.trim()) {
        finalLabel = `${label} (${entry.customerName.trim()})`;
      }
      items.push({ label: finalLabel, amount: amt, remark: entry?.remark });
    }
  };
  addEntry('Husband - Birth Date Proof', q.husband?.birthDateProof);
  addEntry('Husband - Residence Proof', q.husband?.residenceProof);
  addEntry('Husband - Identity Proof', q.husband?.identityProof);
  addEntry('Wife - Birth Date Proof', q.wife?.birthDateProof);
  addEntry('Wife - Residence Proof', q.wife?.residenceProof);
  addEntry('Wife - Identity Proof', q.wife?.identityProof);
  addEntry('Wedding Invitation', q.weddingInvitation);
  addEntry('First Marriage', q.firstMarriage);
  addEntry('Intercaste Marriage', q.intercasteMarriage);
  addEntry('Not Registered Anywhere Else', q.notRegisteredAnywhereElse);

  const consultancyAmt = q.consultancyFee?.amountCharged ?? pricing.marriage_consultancy_fee ?? 500;
  items.push({ label: 'Marriage Registration Consultancy Fee', amount: consultancyAmt });

  if (q.officialFee?.included) {
    let amt = q.officialFee.amountCharged;
    if (amt === undefined || amt === null || amt === 0) {
      if (q.officialFee.duration === 'Upto 3 months')
        amt = pricing.marriage_official_fee_upto_3_months ?? 500;
      else if (q.officialFee.duration === '3 - 12 months')
        amt = pricing.marriage_official_fee_3_to_12_months ?? 600;
      else if (q.officialFee.duration === 'After 12 months')
        amt = pricing.marriage_official_fee_after_12_months ?? 750;
    }
    items.push({ label: `Official Fee (${q.officialFee.duration})`, amount: amt || 0 });
  }

  if (q.courtFeeTickets?.included) {
    const courtFeeAmt = q.courtFeeTickets?.amountCharged;
    const finalCourtFeeAmt =
      courtFeeAmt !== undefined && courtFeeAmt !== null && courtFeeAmt > 0
        ? courtFeeAmt
        : (pricing.marriage_court_fee_tickets ?? 110);
    items.push({ label: 'Court Fee Tickets', amount: finalCourtFeeAmt });
  }

  const uniqueServices = Array.from(new Set(ticket.servicesProvided || []));
  uniqueServices.forEach((svc) => {
    const svcDef = servicesDef.find((s) => s.key === svc);
    if (svcDef) {
      const isMisc = svc === 'Misc (Form - Xerox Copies)';
      const amount =
        isMisc && q.miscFee?.amountCharged !== undefined ? q.miscFee.amountCharged : svcDef.cost;
      items.push({ label: svc, amount });
    }
  });
  return items;
}

import { useState, useEffect, useRef } from 'react';
import { useQuery } from '@tanstack/react-query';
import { affidavitsApi } from '@/api';
import { Affidavit } from '@/types';

interface UseAffidavitLinkerProps {
  setValue: (name: any, value: any) => void;
  phoneWatch: string;
  watchContactName: string;
}

export function useAffidavitLinker({
  setValue,
  phoneWatch,
  watchContactName,
}: UseAffidavitLinkerProps) {
  const [selectedAffidavits, setSelectedAffidavits] = useState<Affidavit[]>([]);
  const [linkedAffs, setLinkedAffs] = useState<Record<string, Affidavit>>({});
  const [activeSearchPurpose, setActiveSearchPurpose] = useState<string | null>(null);
  const [affSearch, setAffSearch] = useState('');
  const [showAffDropdown, setShowAffDropdown] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Fetch affidavits for search dropdown
  const { data: affidavitResults = [] } = useQuery({
    queryKey: ['affidavits-search', affSearch],
    queryFn: () => affidavitsApi.getAll(affSearch ? { search: affSearch } : {}).then((r) => r.data),
    enabled: affSearch.length >= 1,
    staleTime: 30_000,
  });

  // Close dropdown when clicking outside
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setShowAffDropdown(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const selectAffidavit = (aff: Affidavit) => {
    if (selectedAffidavits.some((x) => x.id === aff.id)) {
      setAffSearch('');
      setShowAffDropdown(false);
      return;
    }
    const updated = [...selectedAffidavits, aff];
    setSelectedAffidavits(updated);
    setValue(
      'affidavitIds',
      updated.map((x) => x.id),
    );
    setAffSearch('');
    setShowAffDropdown(false);
  };

  const unlinkAffidavit = (id: string) => {
    const updated = selectedAffidavits.filter((x) => x.id !== id);
    setSelectedAffidavits(updated);
    setValue(
      'affidavitIds',
      updated.map((x) => x.id),
    );
  };

  const linkRequiredAffidavit = (purpose: string, aff: Affidavit) => {
    const next = { ...linkedAffs, [purpose]: aff };
    setLinkedAffs(next);
    setValue(
      'affidavitIds',
      Object.values(next).map((a) => a.id),
    );
    setActiveSearchPurpose(null);
    setAffSearch('');
  };

  const unlinkRequiredAffidavit = (purpose: string) => {
    const next = { ...linkedAffs };
    delete next[purpose];
    setLinkedAffs(next);
    setValue(
      'affidavitIds',
      Object.values(next).map((a) => a.id),
    );
  };

  const startSearch = (purpose: string) => {
    setActiveSearchPurpose(purpose);
    setAffSearch(phoneWatch || watchContactName || '');
    setShowAffDropdown(true);
  };

  const cancelSearch = () => {
    setActiveSearchPurpose(null);
    setAffSearch('');
  };

  const resetLinker = () => {
    setSelectedAffidavits([]);
    setLinkedAffs({});
    setActiveSearchPurpose(null);
    setAffSearch('');
    setShowAffDropdown(false);
  };

  return {
    selectedAffidavits,
    setSelectedAffidavits,
    linkedAffs,
    setLinkedAffs,
    activeSearchPurpose,
    setActiveSearchPurpose,
    affSearch,
    setAffSearch,
    showAffDropdown,
    setShowAffDropdown,
    dropdownRef,
    affidavitsResults: affidavitResults,
    selectAffidavit,
    unlinkAffidavit,
    linkRequiredAffidavit,
    unlinkRequiredAffidavit,
    startSearch,
    cancelSearch,
    resetLinker,
  };
}

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '@/context/AuthContext';
import { authApi } from '@/api';
import styles from './ProfileModal.module.css';

interface ProfileModalProps {
  onClose: () => void;
}

export default function ProfileModal({ onClose }: ProfileModalProps) {
  const { user, updateUser } = useAuth();
  const [name, setName] = useState(user?.name || '');
  const [signature, setSignature] = useState(user?.signature || '');
  const [isDrawing, setIsDrawing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [activeTab, setActiveTab] = useState<'draw' | 'upload'>('draw');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize canvas if user already has a signature and we are in 'draw' tab
  useEffect(() => {
    if (activeTab === 'draw' && signature && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const img = new Image();
        img.onload = () => {
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          // Center and scale image inside canvas
          const scale = Math.min(canvas.width / img.width, canvas.height / img.height) * 0.9;
          const x = (canvas.width - img.width * scale) / 2;
          const y = (canvas.height - img.height * scale) / 2;
          ctx.drawImage(img, x, y, img.width * scale, img.height * scale);
        };
        img.src = signature;
      }
    }
  }, [activeTab, signature]);

  // Handle drawing events
  const getCoordinates = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();

    // Check if touch event
    if ('touches' in e) {
      if (e.touches.length === 0) return { x: 0, y: 0 };
      return {
        x: e.touches[0].clientX - rect.left,
        y: e.touches[0].clientY - rect.top,
      };
    } else {
      return {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      };
    }
  };

  const startDrawing = (
    e: React.MouseEvent<HTMLCanvasElement> | React.TouchEvent<HTMLCanvasElement>,
  ) => {
    e.preventDefault();
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { x, y } = getCoordinates(e);
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.strokeStyle = '#1e3a8a'; // Premium dark blue ink color
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement> | React.TouchEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    e.preventDefault();

    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { x, y } = getCoordinates(e);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);
    // Export signature as base64 string
    saveCanvasToState();
  };

  const saveCanvasToState = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Check if canvas is empty
    const isEmpty = isCanvasEmpty(canvas);
    if (!isEmpty) {
      const dataUrl = canvas.toDataURL('image/png');
      setSignature(dataUrl);
    } else {
      setSignature('');
    }
  };

  const isCanvasEmpty = (canvas: HTMLCanvasElement) => {
    const ctx = canvas.getContext('2d');
    if (!ctx) return true;
    const buffer = new Uint32Array(ctx.getImageData(0, 0, canvas.width, canvas.height).data.buffer);
    return !buffer.some((color) => color !== 0);
  };

  const clearCanvas = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
    }
    setSignature('');
  };

  // Handle Image Upload
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      setError('Please select an image file (PNG/JPG)');
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const dataUrl = event.target?.result as string;
      setSignature(dataUrl);
      setError('');
    };
    reader.onerror = () => {
      setError('Failed to read signature file');
    };
    reader.readAsDataURL(file);
  };

  // Handle Form Submission
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      setError('Name is required');
      return;
    }

    setSaving(true);
    setError('');
    setSuccess(false);

    try {
      const res = await authApi.updateProfile({
        name: name.trim(),
        signature: signature || undefined,
      });
      // Update local context
      updateUser({
        name: res.data.name,
        signature: res.data.signature,
      });
      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        onClose();
      }, 1500);
    } catch (err: any) {
      setError(err?.response?.data?.message || 'Failed to save profile details.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={styles.overlay}>
      <div className={`card modal-card ${styles.modalCard}`}>
        {/* Close Button */}
        <button onClick={onClose} className={styles.closeBtn}>
          Γ£ò
        </button>

