  const [selectedTables, setSelectedTables] = useState<Set<string>>(new Set(ALL_SYNC_TABLES));
  const [exporting, setExporting] = useState(false);

  const toggleTable = (table: string) => {
    setSelectedTables((prev) => {
      const next = new Set(prev);
      if (next.has(table)) next.delete(table);
      else next.add(table);
      return next;
    });
  };

  const toggleCategory = (category: SyncTableCategory, select: boolean) => {
    setSelectedTables((prev) => {
      const next = new Set(prev);
      for (const table of category.tables) {
        if (select) next.add(table);
        else next.delete(table);
      }
      return next;
    });
  };

  const selectAll = () => setSelectedTables(new Set(ALL_SYNC_TABLES));
  const deselectAll = () => setSelectedTables(new Set<string>());

  const exportSyncFile = async () => {
    if (selectedTables.size === 0) {
      toast.error('Select at least one table to export.');
      return;
    }
    setExporting(true);
    try {
      const params = { tables: Array.from(selectedTables).join(',') };
      const res = await api.get('/settings/sync/export', {
        params,
        responseType: 'blob',
        timeout: 300_000,
      });
      const blob = new Blob([res.data], { type: 'application/json' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      const disposition = res.headers['content-disposition'] || '';
      const match = disposition.match(/filename="?(.+?)"?$/);
      a.href = url;
      a.download = match ? match[1] : `sync_${new Date().toISOString().slice(0, 10)}.json`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
      toast.success('Sync file downloaded successfully.');
    } catch (err: any) {
      toast.error(err.response?.data?.message || err.message || 'Failed to export sync file.');
    } finally {
      setExporting(false);
    }
  };

  return {
    categories: SYNC_TABLE_CATEGORIES,
    allTables: ALL_SYNC_TABLES,
    selectedTables,
    toggleTable,
    toggleCategory,
    selectAll,
    deselectAll,
    exporting,
    exportSyncFile,
  };
}

export type SyncExportHook = ReturnType<typeof useSyncExport>;

import { useState } from 'react';
import { api } from '@/api';
import { useToast } from '@/context/ToastContext';
import type { SyncPreviewResult, SyncImportResult } from '@/types';

export function useSyncImport() {
  const toast = useToast();
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<SyncPreviewResult | null>(null);
  const [importing, setImporting] = useState(false);
  const [previewing, setPreviewing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const clearPreview = () => {
    setPreview(null);
    setError(null);
  };

  const updateFile = (nextFile: File | null) => {
    setFile(nextFile);
    setPreview(null);
    setError(null);
  };

  const previewSyncFile = async () => {
    if (!file) {
      setError('Choose a JSON sync file first.');
      return;
    }
    setPreviewing(true);
    setError(null);
    try {
      const text = await file.text();
      JSON.parse(text);
      const res = await api.post<SyncPreviewResult>('/settings/sync/preview', createFormData(file));
      setPreview(res.data);
    } catch (err: any) {
      setError(
        err.response?.data?.message ||
          err.message ||
          'Preview failed. Ensure the file is valid JSON sync data.',
      );
      setPreview(null);
    } finally {
      setPreviewing(false);
    }
  };

  const importSyncFile = async () => {
    if (!file) {
      setError('Choose a JSON sync file first.');
      return;
    }
    setImporting(true);
    setError(null);
    try {
      const res = await api.post<SyncImportResult>('/settings/sync/import', createFormData(file), {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 600_000,
      });
      toast.success(
        `Import completed: ${res.data.inserted} inserted, ${res.data.skipped} skipped.`,
      );
      setFile(null);
      setPreview(null);
    } catch (err: any) {
      setError(err.response?.data?.message || err.message || 'Import failed.');
    } finally {
      setImporting(false);
    }
  };

  return {
    file,
    updateFile,
    preview,
    error,
    previewing,
    importing,
    clearPreview,
    previewSyncFile,
    importSyncFile,
  };
}

export type SyncImportHook = ReturnType<typeof useSyncImport>;

function createFormData(file: File) {
  const formData = new FormData();
  formData.append('file', file);
  return formData;
}

