          </div>
          <div>
            <span style={{ color: 'var(--text-muted)', display: 'block' }}>Token No</span>
            <span style={{ fontWeight: 500 }}>{record.tokenNo || 'ΓÇö'}</span>
          </div>
          <div>
            <span style={{ color: 'var(--text-muted)', display: 'block' }}>Date of Service</span>
            <span style={{ fontWeight: 500 }}>{record.dateOfService}</span>
          </div>
          <div>
            <span style={{ color: 'var(--text-muted)', display: 'block' }}>Business</span>
            <span style={{ fontWeight: 500 }}>{record.business?.name || 'ΓÇö'}</span>
          </div>
        </div>

        {/* Financial Summary */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr 1fr',
            gap: 8,
            marginBottom: '1.5rem',
          }}
        >
          <div
            style={{
              textAlign: 'center',
              padding: '12px 8px',
              background: 'var(--accent-light)',
              border: '2px solid var(--border)',
              borderRadius: 'var(--radius)',
              boxShadow: '2px 2px 0px var(--border)',
            }}
          >
            <div
              style={{
                fontSize: '11px',
                fontWeight: 700,
                color: 'var(--text-muted)',
                marginBottom: 4,
                textTransform: 'uppercase',
              }}
            >
              Total Cost
            </div>
            <div style={{ fontSize: '18px', fontWeight: 800 }}>
              Γé╣{amountCharged.toLocaleString('en-IN')}
            </div>
          </div>
          <div
            style={{
              textAlign: 'center',
              padding: '12px 8px',
              background: 'var(--success-bg)',
              border: '2px solid var(--border)',
              borderRadius: 'var(--radius)',
              boxShadow: '2px 2px 0px var(--border)',
            }}
          >
            <div
              style={{
                fontSize: '11px',
                fontWeight: 700,
                color: 'var(--text-muted)',
                marginBottom: 4,
                textTransform: 'uppercase',
              }}
            >
              Paid
            </div>
            <div style={{ fontSize: '18px', fontWeight: 800 }}>
              Γé╣{totalPaid.toLocaleString('en-IN')}
            </div>
          </div>
          <div
            style={{
              textAlign: 'center',
              padding: '12px 8px',
              background: balance > 0 ? 'var(--danger-bg)' : 'var(--success-bg)',
              border: '2px solid var(--border)',
              borderRadius: 'var(--radius)',
              boxShadow: '2px 2px 0px var(--border)',
            }}
          >
            <div
              style={{
                fontSize: '11px',
                fontWeight: 700,
                color: 'var(--text-muted)',
                marginBottom: 4,
                textTransform: 'uppercase',
              }}
            >
              Balance
            </div>
            <div style={{ fontSize: '18px', fontWeight: 800 }}>
              Γé╣{balance.toLocaleString('en-IN')}
            </div>
          </div>
        </div>

        {/* Payments History */}
        <div style={{ marginBottom: '1rem' }}>
          <div
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginBottom: 8,
            }}
          >
            <span style={{ fontSize: 14, fontWeight: 700, textTransform: 'uppercase' }}>
              Payment History
            </span>
            <button
              className="btn btn-sm btn-primary"
              onClick={() => setShowAddForm(!showAddForm)}
              style={{ fontSize: 12 }}
