          </div>

          {payments.length === 0 && !showAddForm ? (
            <div
              style={{
                padding: '20px',
                textAlign: 'center',
                color: 'var(--text-muted)',
                fontSize: 13,
                border: '2px dashed var(--border-light)',
                borderRadius: 'var(--radius)',
