import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { AuthUser } from '@/types';
import { authApi } from '@/api';

interface AuthContextValue {
  user: AuthUser | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<string>;
  loginWithPasskey: (sessionId: string, credential: any) => Promise<void>;
  logout: () => void;
  isAdmin: boolean;
  updateUser: (updated: Partial<AuthUser>) => void;
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [loading, setLoading] = useState(true);

  const logout = useCallback(() => {
    setLoading(true);
    setTimeout(() => {
      localStorage.removeItem('token');
      setUser(null);
      setLoading(false);
    }, 1200);
  }, []);

  useEffect(() => {
    let authFinished = false;
    let timerFinished = false;
    let resolvedUser: AuthUser | null = null;
    let tokenRemoved = false;

    const checkFinished = () => {
      if (authFinished && timerFinished) {
        if (tokenRemoved) {
          localStorage.removeItem('token');
        }
        setUser(resolvedUser);
        setLoading(false);
      }
    };

    // 1. Minimum 1.5 second splash timer
    const timer = setTimeout(() => {
      timerFinished = true;
      checkFinished();
    }, 1500);

    // 2. Perform the actual auth check
    const token = localStorage.getItem('token');
    if (!token) {
      authFinished = true;
      checkFinished();
    } else {
      authApi
        .me()
        .then((res) => {
          resolvedUser = res.data;
        })
        .catch(() => {
          tokenRemoved = true;
        })
        .finally(() => {
          authFinished = true;
          checkFinished();
        });
    }

    return () => clearTimeout(timer);
  }, []);

  const login = async (email: string, password: string): Promise<string> => {
    const res = await authApi.login(email, password);
    setLoading(true);
    localStorage.setItem('token', res.data.accessToken);
    await new Promise((resolve) => setTimeout(resolve, 1200));
    setUser(res.data.user);
    setLoading(false);
    return res.data.accessToken;
  };

  const loginWithPasskey = async (sessionId: string, credential: any) => {
    const res = await authApi.verifyPasskeyLogin(sessionId, credential);
    setLoading(true);
    localStorage.setItem('token', res.data.accessToken);
    await new Promise((resolve) => setTimeout(resolve, 1200));
    setUser(res.data.user);
    setLoading(false);
  };

  useEffect(() => {
    const handleUnauthorized = () => {
      setUser(null);
    };
    window.addEventListener('auth:unauthorized', handleUnauthorized);
    return () => {
      window.removeEventListener('auth:unauthorized', handleUnauthorized);
    };
  }, []);

  const updateUser = useCallback((updated: Partial<AuthUser>) => {
    setUser((prev) => (prev ? { ...prev, ...updated } : null));
  }, []);

  return (
    <AuthContext.Provider
      value={{
        user,
        loading,
        login,
        loginWithPasskey,
        logout,
        isAdmin: user?.role === 'admin',
        updateUser,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

import { renderHook, act } from '@testing-library/react';
import useIsMobile from '../useIsMobile';

describe('useIsMobile', () => {
  it('returns true for mobile-sized viewport', () => {
    window.innerWidth = 500;
    const { result } = renderHook(() => useIsMobile(768));
    expect(result.current).toBe(true);
  });

  it('returns false for desktop-sized viewport', () => {
    window.innerWidth = 1024;
    const { result } = renderHook(() => useIsMobile(768));
    expect(result.current).toBe(false);
  });

  it('updates when matchMedia fires change event', () => {
    window.innerWidth = 1024;
    const { result } = renderHook(() => useIsMobile(768));
    expect(result.current).toBe(false);

    act(() => {
      const handler = (window as any).__matchMediaHandler;
      handler({ matches: true });
    });
    expect(result.current).toBe(true);
  });
});

import { useReactToPrint } from 'react-to-print';
import { registerPlugin } from '@capacitor/core';

interface PrinterPlugin {
  printHtml(options: { html: string }): Promise<void>;
}

const Printer = registerPlugin<PrinterPlugin>('Printer');

// Safely check if running in a Capacitor environment
const isCapacitor = typeof window !== 'undefined' && (window as any).Capacitor;

export function useAppPrint(options: Parameters<typeof useReactToPrint>[0]) {
  const finalOptions = { ...options };

  if (isCapacitor) {
    finalOptions.print = async (printIframe: HTMLIFrameElement) => {
      const doc = printIframe.contentDocument || printIframe.contentWindow?.document;
      if (!doc) {
        throw new Error('Print iframe document is not accessible');
      }

      // Extract full HTML with stylesheet copies made by react-to-print
      const htmlContent = doc.documentElement.outerHTML;

      try {
        if (Printer && Printer.printHtml) {
          await Printer.printHtml({ html: htmlContent });
        } else {
          // eslint-disable-next-line no-console
          console.warn('Native Printer plugin not found, falling back to browser window.print()');
          printIframe.contentWindow?.print();
        }
      } catch (err) {
        // eslint-disable-next-line no-console
        console.error('Error executing native print:', err);
        printIframe.contentWindow?.print();
      }
    };
  }

  return useReactToPrint(finalOptions);
}

