          <div style={{ fontSize: 20, fontWeight: 500 }}>Gurav Online Services</div>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Email or Name</label>
            <input
              type="text"
              value={email}
