          </>
        )}
      </div>

      {/* Details Modal */}
      {selectedLog && (
        <Modal title="≡ƒÆ¼ Message Dispatch Detail" onClose={() => setSelectedLog(null)}>
          <div style={{ padding: '4px' }}>
            <div className="grid-2" style={{ gap: '12px', marginBottom: '16px' }}>
              <div>
                <span style={{ fontSize: 11, color: 'var(--text-muted)', display: 'block' }}>
                  Recipient Name
                </span>
                <span style={{ fontSize: 13, fontWeight: 600 }}>
                  {selectedLog.recipientName || 'ΓÇö'}
                </span>
              </div>
              <div>
                <span style={{ fontSize: 11, color: 'var(--text-muted)', display: 'block' }}>
                  Recipient Phone
                </span>
                <span style={{ fontSize: 13, fontWeight: 600 }}>{selectedLog.recipientPhone}</span>
              </div>
              <div>
                <span style={{ fontSize: 11, color: 'var(--text-muted)', display: 'block' }}>
                  Module
                </span>
                <span style={{ fontSize: 13, fontWeight: 600 }}>
                  {MODULE_LABEL_MAP[selectedLog.module] || selectedLog.module}
                </span>
              </div>
              <div>
                <span style={{ fontSize: 11, color: 'var(--text-muted)', display: 'block' }}>
