    if (!config) return;
    const exportParams = {
      ...(debouncedSearch ? { search: debouncedSearch } : {}),
      ...(from ? { from } : {}),
      ...(to ? { to } : {}),
      ...(subTab === 'affidavits' && authorizerType ? { authorizerType } : {}),
