        {printRecord &&
          (() => {
            const ReceiptComp = RECEIPT_MAP[printRecord.type];
            return ReceiptComp ? (
              <div ref={receiptRef}>
                <ReceiptComp record={printRecord.data} />
              </div>
            ) : null;
          })()}
      </div>
    </div>
  );
}

import { useState } from 'react';
