export default function ResetPasswordPage() {
  const { logout } = useAuth();
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (password.length < 6) {
      setError('Password must be at least 6 characters long.');
      return;
    }

    if (password !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    setLoading(true);
    try {
      await authApi.resetPassword(password);
      setSuccess('Password updated successfully! Redirecting to login...');
      setTimeout(() => {
        logout();
      }, 2000);
    } catch (err: any) {
      setError(err.response?.data?.message || 'Failed to reset password. Please try again.');
      setLoading(false);
    }
  };

  return (
    <div
      style={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'var(--bg)',
        padding: '1rem',
      }}
    >
      <div className="card" style={{ width: '100%', maxWidth: 380, padding: '2rem' }}>
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            textAlign: 'center',
            marginBottom: 24,
          }}
        >
          <img src="../public/G.png" width="100px" height="100px" style={{ marginBottom: 12 }} />
          <div style={{ fontSize: 20, fontWeight: 500 }}>Reset Default Password</div>
          <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 4 }}>
            For security, please change your password on first login.
          </div>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>New Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Min. 6 characters"
              required
              autoFocus
            />
          </div>
          <div className="form-group">
            <label>Confirm New Password</label>
            <input
              type="password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              placeholder="Re-enter new password"
              required
            />
          </div>
          {error && (
            <div className="alert-error" style={{ marginBottom: 12 }}>
              {error}
            </div>
          )}
          {success && (
            <div className="alert-success" style={{ marginBottom: 12 }}>
              {success}
            </div>
          )}
          <button
            className="btn btn-primary"
            style={{ width: '100%', marginTop: 4 }}
            disabled={loading}
          >
            {loading ? 'Updating passwordΓÇª' : 'Reset Password'}
          </button>
        </form>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { authApi, api } from '@/api';
import { startRegistration } from '@simplewebauthn/browser';
import { biometricService } from '@/services/biometric';
import { Capacitor } from '@capacitor/core';
import { useAuth } from '@/context/AuthContext';
import { useToast } from '@/context/ToastContext';

// Hooks & Subcomponents
import { useSettingsData } from '@/components/Settings/hooks/useSettingsData';
import { useSyncExport } from '@/components/Settings/hooks/useSyncExport';
import { useSyncImport } from '@/components/Settings/hooks/useSyncImport';
import PricingCard from '@/components/Settings/components/PricingCard';
import BiometricCard from '@/components/Settings/components/BiometricCard';
import DatabaseBackupCard from '@/components/Settings/components/DatabaseBackupCard';

export default function SettingsPage() {
  const toast = useToast();
  const { isAdmin } = useAuth();

  // Custom hook for settings pricing logic
  const settingsData = useSettingsData();
  const {
    isLoading,
    editValues,
    dirty,
    resetConfirm,
    setResetConfirm,
    handleChange,
    handleSave,
    groups,
    resetMutation,
    updateMutation,
  } = settingsData;

  const [reduceAnimations, setReduceAnimations] = useState(() => {
    if (typeof window === 'undefined') return false;
    return localStorage.getItem('reduce_animations') === 'true';
  });

  const handleToggleReduceAnimations = (checked: boolean) => {
    setReduceAnimations(checked);
    localStorage.setItem('reduce_animations', checked ? 'true' : 'false');
    toast.success(checked ? 'Animations reduced successfully!' : 'Curtain transitions restored!');
  };

  const [registeringPasskey, setRegisteringPasskey] = useState(false);

  // Native biometric state
  const [biometricHardwareAvailable, setBiometricHardwareAvailable] = useState(false);
  const [biometricEnrolled, setBiometricEnrolled] = useState(false);
  const [biometricSaved, setBiometricSaved] = useState(false);
  const [biometricEnrolling, setBiometricEnrolling] = useState(false);
  const [showPasskeyOption, setShowPasskeyOption] = useState(true);

  // Database management state
  const [exporting, setExporting] = useState(false);
  const [importing, setImporting] = useState(false);
  const [importMode, setImportMode] = useState<'full' | 'insert'>('insert');
  const [importFile, setImportFile] = useState<File | null>(null);
  const [showRestoreConfirm, setShowRestoreConfirm] = useState(false);
  const [restoreConfirmText, setRestoreConfirmText] = useState('');
  const [restoreConfirmChecked, setRestoreConfirmChecked] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Clear database state
  const [clearing, setClearing] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [clearConfirmText, setClearConfirmText] = useState('');
  const [clearConfirmChecked, setClearConfirmChecked] = useState(false);

  const syncExport = useSyncExport();
  const syncImport = useSyncImport();

  useEffect(() => {
    if (Capacitor.isNativePlatform()) {
      const ua = navigator.userAgent;
      const match = ua.match(/Android\s+([0-9]+)/);
      if (match) {
        const androidVer = parseInt(match[1], 10);
        if (androidVer < 11) {
          setShowPasskeyOption(false);
        }
      }
    }

    biometricService.checkBiometricStatus().then(async (status) => {
      setBiometricHardwareAvailable(status.hasHardware);
      setBiometricEnrolled(status.hasEnrolled);
      if (status.hasEnrolled) {
        const hasToken = await biometricService.hasSavedToken();
        setBiometricSaved(hasToken);
      }
    });
  }, []);

  const handleRegisterPasskey = async () => {
    setRegisteringPasskey(true);
    try {
      const res = await authApi.getPasskeyRegisterOptions();
      const { options, sessionId } = res.data;
      const regResult = await startRegistration(options);
      await authApi.verifyPasskeyRegister(sessionId, regResult);
      toast.success('Passkey registered successfully!');
    } catch (err: any) {
      // eslint-disable-next-line no-console
      console.error('[Passkey Register Error]', err);
      if (err.name === 'NotAllowedError') {
        toast.error('Registration cancelled or timed out.');
      } else {
        toast.error(
          err.response?.data?.message || err.message || 'Failed to register biometric credential.',
        );
      }
    } finally {
      setRegisteringPasskey(false);
    }
  };

  const handleEnrollBiometric = async () => {
    setBiometricEnrolling(true);
    try {
      const token = await biometricService.getTokenWithBiometric();
      if (!token) {
        const currentToken = localStorage.getItem('token');
        if (currentToken) {
          await biometricService.saveToken(currentToken);
          setBiometricSaved(true);
          toast.success('Fingerprint authentication configured!');
        } else {
          toast.error(
            'Session not found. Please log out and log in again to enable fingerprint login.',
          );
        }
      } else {
        setBiometricSaved(true);
        toast.success('Fingerprint authentication configured!');
      }
    } catch (err: any) {
      toast.error(err.message || 'Failed to register fingerprint.');
    } finally {
      setBiometricEnrolling(false);
    }
  };

  const handleRemoveBiometric = async () => {
    await biometricService.deleteToken();
    setBiometricSaved(false);
    toast.info('Fingerprint authentication disabled.');
  };

  const handleExportDatabase = async () => {
    setExporting(true);
    try {
      const res = await api.get('/settings/database/export', { responseType: 'blob' });
      const blob = new Blob([res.data], { type: 'application/octet-stream' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      const disposition = res.headers['content-disposition'] || '';
      const match = disposition.match(/filename="?(.+?)"?$/);
      a.href = url;
      a.download = match
        ? match[1]
        : `db_backup_${new Date().toISOString().slice(0, 19).replace(/[:.]/g, '-')}.dump`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
      toast.success('Database exported successfully.');
    } catch (err: any) {
      if (err.response?.data instanceof Blob) {
        try {
          const text = await err.response.data.text();
          const json = JSON.parse(text);
          toast.error(json.message || 'Export failed.');
        } catch {
          toast.error('Export failed. Check server logs.');
        }
      } else {
        toast.error(err.response?.data?.message || err.message || 'Export failed.');
      }
    } finally {
      setExporting(false);
    }
  };

  const handleImportDatabase = async () => {
    if (!importFile) return;
    if (importMode === 'full' && !showRestoreConfirm) {
      setShowRestoreConfirm(true);
      return;
    }
    setShowRestoreConfirm(false);
    setRestoreConfirmText('');
    setRestoreConfirmChecked(false);
    setImporting(true);
    try {
      const formData = new FormData();
      formData.append('file', importFile);
      formData.append('mode', importMode);
      const res = await api.post('/settings/database/import', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 300_000,
      });
      toast.success(
        res.data?.message || res.data?.data?.message || 'Import completed successfully.',
      );
      setImportFile(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    } catch (err: any) {
      toast.error(err.response?.data?.message || err.message || 'Import failed.');
    } finally {
      setImporting(false);
    }
  };

  const handleClearDatabase = async () => {
    if (!showClearConfirm) {
      setShowClearConfirm(true);
      return;
    }
    setShowClearConfirm(false);
    setClearConfirmText('');
    setClearConfirmChecked(false);
    setClearing(true);
    try {
      const res = await api.post('/settings/database/clear');
      toast.success(
        res.data?.message || 'All transactional database records cleared successfully.',
      );
    } catch (err: any) {
      toast.error(
        err.response?.data?.message || err.message || 'Failed to clear database records.',
      );
    } finally {
      setClearing(false);
    }
  };

  const groupLabels: Record<string, string> = {
    property_card: 'Property Card rates',
    shop_act: 'Shop Act License rates',
    affidavit: 'Affidavit / Notary rates',
    marriage: 'Marriage Registration rates',
    birth_death: 'Birth / Death Certificate rates',
    trade_license: 'Trade License rates',
    csc: 'CSC Services rates',
    aaple_sarkar: 'Aaple Sarkar / Gazette rates',
    water_supply: 'Water Supply rates',
    property_tax: 'Property Tax rates',
  };

  return (
    <div>
      <div className="page-header">
        <div className="page-title">Pricing Settings</div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          {dirty.size > 0 && (
            <button
              className="btn btn-primary"
              onClick={handleSave}
              disabled={updateMutation.isPending}
            >
              {updateMutation.isPending
                ? 'SavingΓÇª'
                : `Save ${dirty.size} change${dirty.size > 1 ? 's' : ''}`}
            </button>
          )}
          <button
            className="btn"
            style={{ color: 'var(--danger)' }}
            onClick={() => setResetConfirm(true)}
          >
            Reset to defaults
          </button>
        </div>
      </div>

      <div
        style={{
          background: 'var(--accent-light)',
          border: '0.5px solid rgba(24,95,165,0.25)',
          borderRadius: 'var(--radius)',
          padding: '12px 16px',
          fontSize: 13,
          color: 'var(--text)',
          marginBottom: '1.5rem',
          display: 'flex',
          gap: 10,
          alignItems: 'flex-start',
        }}
      >
        <span style={{ fontSize: 16 }}>Γä╣∩╕Å</span>
        <div>
          <strong>Changes take effect immediately.</strong> The price calculator and all add-record
          forms pull rates from this table in real time ΓÇö no restart needed. Previously saved
          records are not affected.
        </div>
      </div>

      {isLoading ? (
        <div style={{ color: 'var(--text-muted)', fontSize: 14 }}>Loading pricingΓÇª</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          {[
            'affidavit',
            'marriage',
            'birth_death',
            'property_card',
            'shop_act',
            'trade_license',
            'csc',
            'aaple_sarkar',
            'water_supply',
            'property_tax',
          ]
            .filter((g) => groups[g])
            .map((group) => (
              <PricingCard
                key={group}
                group={group}
                groupLabel={groupLabels[group]}
                groupSettings={groups[group]}
                editValues={editValues}
                dirty={dirty}
                handleChange={handleChange}
                handleSave={handleSave}
                isSaving={updateMutation.isPending}
              />
            ))}

          {/* General & Performance Settings */}
          <div
            className="card"
            style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}
          >
            <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
              <div
                style={{
                  fontSize: '18px',
                  fontWeight: 700,
                  color: 'var(--text)',
                  fontFamily: "'Space Grotesk', sans-serif",
                }}
              >
                General Settings
              </div>
              <div style={{ fontSize: '12px', color: 'var(--text-muted)' }}>
                Customize application performance and interface preferences.
              </div>
            </div>

            <div
              style={{ height: '1px', background: 'var(--border)', opacity: 0.5, margin: '4px 0' }}
            />

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                <div style={{ fontSize: '14px', fontWeight: 600, color: 'var(--text)' }}>
                  Reduce Animations & Transitions
                </div>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', maxWidth: '90%' }}>
                  Replaces heavy liquid gooey SVG filter animations with a faster, memory-efficient
                  opacity fade. Highly recommended for slower devices or saving battery.
                </div>
              </div>
              <div>
                <label
                  className="switch"
                  style={{ display: 'inline-block', position: 'relative', width: 48, height: 26 }}
                >
                  <input
                    type="checkbox"
                    checked={reduceAnimations}
                    onChange={(e) => handleToggleReduceAnimations(e.target.checked)}
                    style={{ opacity: 0, width: 0, height: 0 }}
                  />
                  <span
                    className="slider"
                    style={{
                      position: 'absolute',
                      cursor: 'pointer',
                      top: 0,
                      left: 0,
                      right: 0,
                      bottom: 0,
                      backgroundColor: reduceAnimations ? 'var(--accent)' : '#ccc',
                      transition: '0.3s',
                      borderRadius: 34,
                      border: '2px solid var(--border)',
                      boxShadow: reduceAnimations ? '2px 2px 0 var(--border)' : 'none',
                    }}
                  >
                    <span
                      style={{
                        position: 'absolute',
                        content: '""',
                        height: 16,
                        width: 16,
                        left: reduceAnimations ? 24 : 4,
                        bottom: 2,
                        backgroundColor: 'white',
                        transition: '0.3s',
                        borderRadius: '50%',
                        border: '2px solid var(--border)',
                      }}
                    />
                  </span>
                </label>
              </div>
            </div>
          </div>

          {/* Biometrics & Passkeys Card */}
          <BiometricCard
            showPasskeyOption={showPasskeyOption}
            registeringPasskey={registeringPasskey}
            handleRegisterPasskey={handleRegisterPasskey}
            biometricHardwareAvailable={biometricHardwareAvailable}
            biometricEnrolled={biometricEnrolled}
            biometricSaved={biometricSaved}
            biometricEnrolling={biometricEnrolling}
            handleEnrollBiometric={handleEnrollBiometric}
            handleRemoveBiometric={handleRemoveBiometric}
          />

          {/* Database Admin Card (Only visible to Admin) */}
          <DatabaseBackupCard
            isAdmin={isAdmin}
            exporting={exporting}
            handleExportDatabase={handleExportDatabase}
            importing={importing}
            importMode={importMode}
            setImportMode={setImportMode}
            importFile={importFile}
            setImportFile={setImportFile}
            handleImportDatabase={handleImportDatabase}
            showRestoreConfirm={showRestoreConfirm}
            setShowRestoreConfirm={setShowRestoreConfirm}
            restoreConfirmText={restoreConfirmText}
            setRestoreConfirmText={setRestoreConfirmText}
            restoreConfirmChecked={restoreConfirmChecked}
            setRestoreConfirmChecked={setRestoreConfirmChecked}
            fileInputRef={fileInputRef}
            clearing={clearing}
            showClearConfirm={showClearConfirm}
            setShowClearConfirm={setShowClearConfirm}
            clearConfirmText={clearConfirmText}
            setClearConfirmText={setClearConfirmText}
            clearConfirmChecked={clearConfirmChecked}
            setClearConfirmChecked={setClearConfirmChecked}
            handleClearDatabase={handleClearDatabase}
            syncExport={syncExport}
            syncImport={syncImport}
          />
        </div>
      )}

      {/* Reset confirmation modal */}
      {resetConfirm && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.6)',
            zIndex: 1000,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: 16,
          }}
        >
          <div className="card" style={{ maxWidth: 400, width: '100%' }}>
            <div style={{ fontWeight: 600, fontSize: 16, marginBottom: 12 }}>
              Reset Pricing Defaults
            </div>
            <p
              style={{
                fontSize: 13,
                color: 'var(--text-muted)',
                lineHeight: 1.5,
                marginBottom: 20,
              }}
            >
              Are you sure you want to reset all service rate values back to their system defaults?
              Unsaved edits will be lost.
            </p>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
              <button className="btn" onClick={() => setResetConfirm(false)}>
                Cancel
              </button>
              <button
                className="btn btn-primary"
                style={{ background: 'var(--danger)', borderColor: 'var(--danger)' }}
                disabled={resetMutation.isPending}
                onClick={() => resetMutation.mutate()}
              >
                {resetMutation.isPending ? 'ResettingΓÇª' : 'Yes, Reset Rates'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useRef } from 'react';
import { useAppPrint } from '@/hooks/useAppPrint';
import { TradeLicenseRecord, Business } from '@/types';
import { TradeLicenseReceipt } from '@/components/ReceiptModal/Receipt';
import ServiceFormsTab from '@/components/TradeLicenses/components/ServiceFormsTab';
import BusinessesListTab from '@/components/TradeLicenses/components/BusinessesListTab';
import RenewalQueueTab from '@/components/TradeLicenses/components/RenewalQueueTab';
import ServiceLogsTab from '@/components/TradeLicenses/components/ServiceLogsTab';
import ConfigsTab from '@/components/TradeLicenses/components/ConfigsTab';
import ShareReceiptModal from '@/components/TradeLicenses/components/ShareReceiptModal';

export default function TradeLicensesPage() {
  const [activeTab, setActiveTab] = useState<
    'forms' | 'businesses' | 'renewal' | 'logs' | 'configs'
  >('forms');
  const [selectedServiceType, setSelectedServiceType] =
    useState<TradeLicenseRecord['serviceType']>('New');
  const [selectedBusiness, setSelectedBusiness] = useState<Business | null>(null);
  const [savedRecord, setSavedRecord] = useState<TradeLicenseRecord | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);

  const receiptRef = useRef<HTMLDivElement>(null);
  const handlePrint = useAppPrint({ content: () => receiptRef.current });

  const startServiceForBusiness = (biz: Business, service: TradeLicenseRecord['serviceType']) => {
    setSelectedBusiness(biz);
    setSelectedServiceType(service);
    setActiveTab('forms');
  };

  const onRecordSaved = (record: TradeLicenseRecord) => {
    setSavedRecord(record);
    setShowSuccessModal(true);
  };

  const onPrintTrigger = (record: TradeLicenseRecord) => {
    setSavedRecord(record);
    setTimeout(handlePrint, 100);
  };

  return (
    <div>
      <div className="page-header">
        <div className="page-title">Trade License Module</div>
      </div>

      {/* Main Tab bar */}
      <div className="tab-bar" style={{ flexWrap: 'wrap', marginBottom: '1.25rem' }}>
        {[
          { key: 'forms', label: 'Service Forms' },
          { key: 'businesses', label: 'Businesses List' },
          { key: 'renewal', label: 'Renewal Queue' },
          { key: 'logs', label: 'Service Logs' },
          { key: 'configs', label: 'Trade Configs' },
        ].map((t) => (
          <button
            key={t.key}
            className={`tab ${activeTab === t.key ? 'active' : ''}`}
            onClick={() => {
              setActiveTab(t.key as any);
              setSavedRecord(null); // clear printed receipt indicator
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* Tab Panels */}
      {activeTab === 'forms' && (
        <ServiceFormsTab
          selectedServiceType={selectedServiceType}
          setSelectedServiceType={setSelectedServiceType}
          selectedBusiness={selectedBusiness}
          setSelectedBusiness={setSelectedBusiness}
          onRecordSaved={onRecordSaved}
        />
      )}

      {activeTab === 'businesses' && (
        <BusinessesListTab startServiceForBusiness={startServiceForBusiness} />
      )}

      {activeTab === 'renewal' && (
        <RenewalQueueTab startServiceForBusiness={startServiceForBusiness} />
      )}

      {activeTab === 'logs' && <ServiceLogsTab onPrint={onPrintTrigger} />}

      {activeTab === 'configs' && <ConfigsTab />}

      {/* Hidden print targets */}
      {savedRecord && (
        <div style={{ position: 'absolute', left: '-9999px', top: 0 }}>
          <TradeLicenseReceipt ref={receiptRef} record={savedRecord} />
        </div>
      )}

      {/* Success Popup Modal */}
      {showSuccessModal && savedRecord && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.6)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999,
            padding: '1rem',
          }}
        >
          <div
            className="card"
            style={{
              maxWidth: 400,
              width: '100%',
              backgroundColor: 'var(--surface)',
              position: 'relative',
              textAlign: 'center',
              padding: '28px 24px',
              boxShadow: '6px 6px 0px var(--border)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              color: 'var(--text)',
            }}
          >
            {/* Close Button */}
            <button
              type="button"
              onClick={() => {
                setShowSuccessModal(false);
                setSavedRecord(null);
              }}
              style={{
                position: 'absolute',
                top: 12,
                right: 12,
                background: 'none',
                border: 'none',
                fontSize: 18,
                fontWeight: 'bold',
                cursor: 'pointer',
                color: 'var(--text)',
              }}
            >
              Γ£ò
            </button>

            {/* Checkmark Icon */}
            <div
              style={{
                width: 54,
                height: 54,
                borderRadius: '50%',
                border: '3.5px solid var(--border)',
                background: '#2ecc71',
                boxShadow: '3px 3px 0px var(--border)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 24,
                fontWeight: 'bold',
                color: '#000000',
                marginBottom: 16,
              }}
            >
              Γ£ô
            </div>

            <h3 style={{ margin: '0 0 8px 0', fontSize: 18, fontWeight: 'bold' }}>Record Saved!</h3>
            <p style={{ margin: '0 0 24px 0', color: 'var(--text-muted)', fontSize: 14 }}>
              The trade license transaction has been successfully registered.
            </p>

            <div style={{ display: 'flex', gap: 12, width: '100%' }}>
              <button
                className="btn btn-primary"
                style={{
                  flex: 1,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 6,
                }}
                onClick={() => {
                  handlePrint();
                }}
              >
                ≡ƒû¿ Print Receipt
              </button>
              <button
                className="btn btn-success-soft"
                style={{
                  flex: 1,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 6,
                }}
                onClick={() => {
                  setShowSuccessModal(false);
                  setShowShareModal(true);
                }}
              >
                ≡ƒÆ¼ Share
              </button>
              <button
                className="btn"
                style={{ flex: 1 }}
                onClick={() => {
                  setShowSuccessModal(false);
                  setSavedRecord(null);
                }}
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {showShareModal && savedRecord && (
        <ShareReceiptModal
          record={savedRecord}
          onClose={() => {
            setShowShareModal(false);
            setSavedRecord(null);
          }}
        />
      )}
    </div>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { usersApi } from '@/api';
import { User, Role } from '@/types';
import { useAuth } from '@/context/AuthContext';
import NeoSelect from '@/components/NeoSelect';
import Modal from '@/components/Modal';

interface UserFormState {
  name: string;
  email: string;
  password: string;
  role: Role;
}

const emptyForm: UserFormState = { name: '', email: '', password: '', role: 'operator' };

export default function UsersPage() {
  const { user: me } = useAuth();
  const qc = useQueryClient();
  const [showAdd, setShowAdd] = useState(false);
  const [editing, setEditing] = useState<User | null>(null);
  const [form, setForm] = useState<UserFormState>(emptyForm);
  const [editForm, setEditForm] = useState<Partial<UserFormState & { isActive: boolean }>>({});
  const [err, setErr] = useState('');

  const { data: users = [], isLoading } = useQuery({
    queryKey: ['users'],
    queryFn: () => usersApi.getAll().then((r) => r.data),
  });

  const createMutation = useMutation({
    mutationFn: (data: UserFormState) => usersApi.create(data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['users'] });
      setShowAdd(false);
      setForm(emptyForm);
      setErr('');
    },
    onError: (e: any) => setErr(e?.response?.data?.message || 'Failed to create user.'),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: typeof editForm }) => usersApi.update(id, data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['users'] });
      setEditing(null);
      setEditForm({});
      setErr('');
    },
    onError: (e: any) => setErr(e?.response?.data?.message || 'Failed to update user.'),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => usersApi.delete(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['users'] }),
  });

  const openEdit = (u: User) => {
    setEditing(u);
    setEditForm({ name: u.name, role: u.role, isActive: u.isActive, password: '' });
    setErr('');
  };

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.password) {
      setErr('All fields are required.');
      return;
    }
    createMutation.mutate(form);
  };

  const handleUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editing) return;
    const payload: typeof editForm = { ...editForm };
    if (!payload.password) delete payload.password;
    delete payload.email;
    updateMutation.mutate({ id: editing.id, data: payload });
  };

  const isAdmin = me?.role === 'admin';

  return (
    <div>
      <div className="page-header">
        <div className="page-title">User management</div>
        {isAdmin && (
          <button
            className="btn btn-primary"
            onClick={() => {
              setShowAdd(true);
              setErr('');
            }}
          >
            + Add user
          </button>
        )}
      </div>

      {isLoading ? (
        <div style={{ color: 'var(--text-muted)', fontSize: 14 }}>LoadingΓÇª</div>
      ) : (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Role</th>
                  <th>Status</th>
                  <th>Created</th>
                  <th style={{ width: 130 }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {users.map((u, i) => (
                  <tr key={u.id}>
                    <td style={{ color: 'var(--text-muted)' }}>{i + 1}</td>
                    <td style={{ fontWeight: 500 }}>
                      {u.name}
                      {u.id === me?.id && (
                        <span className="badge badge-blue" style={{ marginLeft: 6, fontSize: 10 }}>
                          you
                        </span>
                      )}
                    </td>
                    <td style={{ color: 'var(--text-muted)' }}>{u.email}</td>
                    <td>
                      <span
                        className={`badge ${u.role === 'admin' ? 'badge-amber' : 'badge-blue'}`}
                      >
                        {u.role}
                      </span>
                    </td>
                    <td>
                      <span className={`badge ${u.isActive ? 'badge-green' : 'badge-red'}`}>
                        {u.isActive ? 'Active' : 'Inactive'}
                      </span>
                    </td>
                    <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>
                      {new Date(u.createdAt).toLocaleDateString('en-IN')}
                    </td>
                    <td>
                      <div style={{ display: 'flex', gap: 4 }}>
                        <button className="btn btn-sm" onClick={() => openEdit(u)}>
                          Edit
                        </button>
                        {u.id !== me?.id && (
                          <button
                            className="btn btn-sm btn-danger"
                            onClick={() => {
                              if (confirm(`Delete user "${u.name}"? This cannot be undone.`))
                                deleteMutation.mutate(u.id);
                            }}
                          >
                            Del
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
                {users.length === 0 && (
                  <tr>
                    <td
                      colSpan={7}
                      style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '2rem' }}
                    >
                      No users found.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Add user modal */}
      {showAdd && (
        <Modal
          title="Add new user"
          onClose={() => {
            setShowAdd(false);
            setErr('');
            setForm(emptyForm);
          }}
        >
          <form onSubmit={handleCreate}>
            <div className="form-group">
              <label>Full name *</label>
              <input
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                placeholder="e.g. Akash Patil"
                autoFocus
              />
            </div>
            <div className="form-group">
              <label>Email address *</label>
              <input
                type="email"
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
                placeholder="user@example.com"
              />
            </div>
            <div className="form-group">
              <label>Password *</label>
              <input
                type="password"
                value={form.password}
                onChange={(e) => setForm({ ...form, password: e.target.value })}
                placeholder="Min. 6 characters"
              />
            </div>
            <div className="form-group">
              <label>Role</label>
              <NeoSelect
                value={form.role}
                onChange={(val) => setForm({ ...form, role: val as Role })}
                options={[
                  { value: 'operator', label: 'Operator ΓÇö can add & edit records' },
                  { value: 'admin', label: 'Admin ΓÇö full access + user management' },
                ]}
              />
              <div style={{ fontSize: 12, color: 'var(--text-hint)', marginTop: 4 }}>
                Operators cannot delete records or manage users.
              </div>
            </div>
            {err && (
              <div className="alert-error" style={{ marginBottom: 12 }}>
                {err}
              </div>
            )}
            <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
              <button className="btn btn-primary" type="submit" disabled={createMutation.isPending}>
                {createMutation.isPending ? 'CreatingΓÇª' : 'Create user'}
              </button>
              <button
                type="button"
                className="btn"
                onClick={() => {
                  setShowAdd(false);
                  setErr('');
                  setForm(emptyForm);
                }}
              >
                Cancel
              </button>
            </div>
          </form>
        </Modal>
      )}

      {/* Edit user modal */}
      {editing && (
        <Modal
          title={`Edit ΓÇö ${editing.name}`}
          onClose={() => {
            setEditing(null);
            setErr('');
          }}
        >
          <form onSubmit={handleUpdate}>
            <div className="form-group">
              <label>Full name</label>
              <input
                value={editForm.name || ''}
                onChange={(e) => setEditForm({ ...editForm, name: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label>New password</label>
              <input
                type="password"
                value={editForm.password || ''}
                onChange={(e) => setEditForm({ ...editForm, password: e.target.value })}
